@tailwind base;
@tailwind components;
@tailwind utilities;

/* Fonts */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');

/* Leaflet Map Styles */
@import 'leaflet/dist/leaflet.css';

:root {
  --canvas: #0A0A0A;
  --panel: #141414;
  --elevated: #1C1C1C;
  --hover: #262626;
  --border: #2A2A2A;
  --text-primary: #FAFAFA;
  --text-secondary: #A1A1A1;
  --text-muted: #6B6B6B;
}

body {
  color: var(--text-primary);
  background-color: var(--canvas);
  font-family: 'Inter', system-ui, sans-serif;
}

/* Railway Domain Typography */
.train-id {
  font-family: 'JetBrains Mono', 'Monaco', 'Menlo', monospace;
  font-weight: 600;
}

.km-value {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums;
}

/* Scrollbar styling for dark mode */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: var(--panel);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--hover);
}

/* Map container dark mode */
.leaflet-container {
  background-color: var(--canvas);
}

/* Custom focus states */
*:focus-visible {
  outline: 2px solid #3b82f6;
  outline-offset: 2px;
}

'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';

const navItems = [
  { href: '/', label: 'Dashboard' },
  { href: '/map', label: 'Map' },
  { href: '/allocation', label: 'Allocation' },
  { href: '/fleet', label: 'Fleet' },
  { href: '/balancing', label: 'Balancing' },
  { href: '/schedule', label: 'Schedule' },
  { href: '/maintenance', label: 'Maintenance' },
];

/**
 * Main Navigation Component
 *
 * Provides navigation links to all main pages.
 * Highlights the current active page.
 */
export function Navigation() {
  const pathname = usePathname();

  return (
    <nav className="bg-panel border-b border-border">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center">
            <Link href="/" className="flex items-center">
              <span className="text-xl font-bold text-primary-500">MMS</span>
              <span className="ml-2 text-sm text-text-muted hidden sm:block">
                Metro Mileage Management
              </span>
            </Link>

            {/* Nav Links */}
            <div className="hidden md:flex ml-10 space-x-1">
              {navItems.map((item) => {
                const isActive = pathname === item.href ||
                  (item.href !== '/' && pathname.startsWith(item.href));

                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                      isActive
                        ? 'bg-primary-600 text-white'
                        : 'text-text-secondary hover:bg-hover hover:text-text-primary'
                    }`}
                  >
                    {item.label}
                  </Link>
                );
              })}
            </div>
          </div>

          {/* Demo Badge */}
          <div className="flex items-center">
            <span className="px-2 py-1 text-xs font-medium bg-amber-500/20 text-amber-400 rounded">
              DEMO
            </span>
          </div>
        </div>
      </div>
    </nav>
  );
}

