'use client';

import React from 'react';

interface KPICardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  borderColor?: string;
  icon?: React.ReactNode;
  loading?: boolean;
  tooltip?: string;
  onClick?: () => void;
}

/**
 * KPI Card Component
 *
 * Displays a single KPI metric with title, value, and optional subtitle.
 * Uses EN 15380 railway terminology.
 */
export function KPICard({
  title,
  value,
  subtitle,
  borderColor = 'border-primary-500',
  icon,
  loading = false,
  tooltip,
  onClick,
}: KPICardProps) {
  return (
    <div
      className={`bg-panel rounded-lg p-4 border-l-4 ${borderColor} transition-all duration-200 hover:bg-elevated ${onClick ? 'cursor-pointer' : ''}`}
      title={tooltip}
      onClick={onClick}
      role={onClick ? 'button' : undefined}
      tabIndex={onClick ? 0 : undefined}
    >
      <div className="flex items-center justify-between">
        <div className="text-sm font-medium text-text-muted">{title}</div>
        {icon && <div className="flex-shrink-0 text-text-secondary">{icon}</div>}
      </div>
      <div className="mt-2">
        {loading ? (
          <div className="animate-pulse">
            <div className="h-8 bg-elevated rounded w-20"></div>
          </div>
        ) : (
          <div className="text-3xl font-bold text-text-primary">{value}</div>
        )}
      </div>
      {subtitle && !loading && (
        <div className="mt-1 text-sm text-text-muted">{subtitle}</div>
      )}
    </div>
  );
}

