/* Blueprint.js Core Styles */
@import "@blueprintjs/core/lib/css/blueprint.css";
@import "@blueprintjs/icons/lib/css/blueprint-icons.css";
@import "@blueprintjs/table/lib/css/table.css";
@import "@blueprintjs/select/lib/css/blueprint-select.css";
@import "@blueprintjs/datetime2/lib/css/blueprint-datetime2.css";

/* Google Fonts */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');

/* Leaflet Map Styles */
@import 'leaflet/dist/leaflet.css';

/* MMS Custom Styles */
:root {
  /* MMS Brand Colors */
  --mms-primary: #2563eb;
  --mms-primary-hover: #1d4ed8;

  /* Status Colors */
  --mms-status-available: #22c55e;
  --mms-status-in-service: #3b82f6;
  --mms-status-maintenance: #ef4444;

  /* Variance Traffic Light */
  --mms-variance-green: #22c55e;
  --mms-variance-yellow: #eab308;
  --mms-variance-red: #ef4444;

  /* Maintenance Types */
  --mms-maint-pm1: #10B981;
  --mms-maint-pm2: #3B82F6;
  --mms-maint-pm3: #F59E0B;
  --mms-maint-overhaul: #EF4444;
}

/* Base body styling */
body {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  margin: 0;
  padding: 0;
}

/* Railway Domain Typography */
.train-id {
  font-family: 'JetBrains Mono', 'Monaco', 'Menlo', monospace;
  font-weight: 600;
}

.km-value {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums;
}

/* Custom scrollbar styling */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: #f1f1f1;
}

::-webkit-scrollbar-thumb {
  background: #c4c4c4;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #a0a0a0;
}

/* Map container */
.leaflet-container {
  background-color: #f8fafc;
}

/* MMS Custom Button Intents */
.bp6-button.mms-available {
  background-color: var(--mms-status-available) !important;
  color: white !important;
}

.bp6-button.mms-maintenance {
  background-color: var(--mms-status-maintenance) !important;
  color: white !important;
}

/* Status Tags */
.mms-status-available {
  background-color: var(--mms-status-available);
  color: white;
}

.mms-status-in-service {
  background-color: var(--mms-status-in-service);
  color: white;
}

.mms-status-maintenance {
  background-color: var(--mms-status-maintenance);
  color: white;
}

/* Variance Tags */
.mms-variance-green {
  background-color: var(--mms-variance-green);
  color: white;
}

.mms-variance-yellow {
  background-color: var(--mms-variance-yellow);
  color: black;
}

.mms-variance-red {
  background-color: var(--mms-variance-red);
  color: white;
}

/* Maintenance Type Tags */
.mms-maint-pm1 {
  background-color: var(--mms-maint-pm1);
  color: white;
}

.mms-maint-pm2 {
  background-color: var(--mms-maint-pm2);
  color: white;
}

.mms-maint-pm3 {
  background-color: var(--mms-maint-pm3);
  color: black;
}

.mms-maint-overhaul {
  background-color: var(--mms-maint-overhaul);
  color: white;
}

/* Grid layout helpers */
.mms-grid-4 {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
}

.mms-grid-3 {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

.mms-grid-2 {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 16px;
}

@media (max-width: 1200px) {
  .mms-grid-4 {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .mms-grid-4,
  .mms-grid-3,
  .mms-grid-2 {
    grid-template-columns: 1fr;
  }
}

/* App Layout */
.mms-app-container {
  min-height: 100vh;
  background-color: #f8fafc;
}

.mms-main-content {
  max-width: 1400px;
  margin: 0 auto;
  padding: 24px;
}

/* Card styling extensions */
.mms-kpi-card {
  border-left: 4px solid var(--mms-primary);
}

.mms-kpi-card.available {
  border-left-color: var(--mms-status-available);
}

.mms-kpi-card.maintenance {
  border-left-color: var(--mms-status-maintenance);
}

.mms-kpi-card.variance-green {
  border-left-color: var(--mms-variance-green);
}

.mms-kpi-card.variance-yellow {
  border-left-color: var(--mms-variance-yellow);
}

.mms-kpi-card.variance-red {
  border-left-color: var(--mms-variance-red);
}

