'use client';

import React from 'react';
import { Card, Elevation, Spinner, Icon, IconName } from '@blueprintjs/core';

interface KPICardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  borderColor?: 'primary' | 'available' | 'maintenance' | 'variance-green' | 'variance-yellow' | 'variance-red';
  icon?: IconName;
  loading?: boolean;
  tooltip?: string;
  onClick?: () => void;
}

/**
 * KPI Card Component
 *
 * Displays a single KPI metric with title, value, and optional subtitle.
 * Uses EN 15380 railway terminology.
 */
export function KPICard({
  title,
  value,
  subtitle,
  borderColor = 'primary',
  icon,
  loading = false,
  tooltip,
  onClick,
}: KPICardProps) {
  const cardClassName = `mms-kpi-card ${borderColor}`;

  return (
    <Card
      elevation={Elevation.ONE}
      interactive={!!onClick}
      onClick={onClick}
      className={cardClassName}
      title={tooltip}
      style={{ padding: 16 }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontSize: 14, fontWeight: 500, color: '#5c7080' }}>{title}</span>
        {icon && <Icon icon={icon} size={20} color="#5c7080" />}
      </div>
      <div style={{ marginTop: 8 }}>
        {loading ? (
          <Spinner size={24} />
        ) : (
          <div style={{ fontSize: 32, fontWeight: 700, color: '#182026' }}>{value}</div>
        )}
      </div>
      {subtitle && !loading && (
        <div style={{ marginTop: 4, fontSize: 14, color: '#5c7080' }}>{subtitle}</div>
      )}
    </Card>
  );
}

