'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Card, Elevation, ProgressBar, Intent, Spinner, Callout, Tag } from '@blueprintjs/core';
import { dashboardApi, DepotCapacity } from '@/lib/api';

interface DepotCardProps {
  depot: DepotCapacity;
  onClick?: () => void;
}

/**
 * Individual Depot Card Component
 */
function DepotCard({ depot, onClick }: DepotCardProps) {
  // Determine intent based on usage percentage
  const getIntent = (percent: number): Intent => {
    if (percent < 70) return Intent.SUCCESS;
    if (percent < 90) return Intent.WARNING;
    return Intent.DANGER;
  };

  const getStatusText = (percent: number): string => {
    if (percent >= 90) return 'Capacity critical';
    if (percent >= 70) return 'High usage';
    return 'Capacity available';
  };

  const intent = getIntent(depot.percentUsed);

  return (
    <Card
      elevation={Elevation.ONE}
      interactive
      onClick={onClick}
      style={{ padding: 16 }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
        <div>
          <div style={{ fontWeight: 600, fontSize: 14, color: '#182026' }}>{depot.name}</div>
          <span className="train-id" style={{ fontSize: 12, color: '#5c7080' }}>{depot.code}</span>
        </div>
        <Tag intent={intent} minimal large>
          {depot.percentUsed}%
        </Tag>
      </div>

      {/* Capacity Bar */}
      <div style={{ marginBottom: 8 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: '#5c7080', marginBottom: 4 }}>
          <span>Tracks</span>
          <span>{depot.currentOccupancy}/{depot.maxCapacity}</span>
        </div>
        <ProgressBar
          value={depot.percentUsed / 100}
          intent={intent}
          stripes={false}
        />
      </div>

      {/* Status Indicator */}
      <Tag intent={intent} minimal style={{ fontSize: 11 }}>
        {getStatusText(depot.percentUsed)}
      </Tag>
    </Card>
  );
}

/**
 * Depot Capacity Cards Component
 *
 * Displays depot occupancy grid showing current vs max capacity
 * with color-coded indicators.
 */
export function DepotCapacityCards() {
  const router = useRouter();
  const [depots, setDepots] = useState<DepotCapacity[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchDepots() {
      setLoading(true);
      const { data, error } = await dashboardApi.getDepotCapacity();

      if (error) {
        setError(error);
      } else if (data) {
        // Sort by usage percentage (highest first)
        const sorted = [...data.depots].sort((a, b) => b.percentUsed - a.percentUsed);
        setDepots(sorted);
      }
      setLoading(false);
    }

    fetchDepots();
  }, []);

  const handleDepotClick = (depotId: string) => {
    router.push(`/fleet?depot=${depotId}`);
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', padding: 32 }}>
        <Spinner size={32} />
      </div>
    );
  }

  if (error) {
    return (
      <Callout intent={Intent.DANGER} title="Error loading depot capacity">
        {error}
      </Callout>
    );
  }

  if (depots.length === 0) {
    return (
      <Callout intent={Intent.NONE}>
        No depot data available
      </Callout>
    );
  }

  return (
    <div className="mms-grid-4">
      {depots.map((depot) => (
        <DepotCard
          key={depot.id}
          depot={depot}
          onClick={() => handleDepotClick(depot.id)}
        />
      ))}
    </div>
  );
}

