'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { dashboardApi, MaintenanceAlertsResponse, MaintenanceAlert } from '@/lib/api';

// Maintenance type colors (dark mode)
const typeColors: Record<string, string> = {
  PM1: 'bg-maint-pm1/20 text-maint-pm1',
  PM2: 'bg-maint-pm2/20 text-maint-pm2',
  HM: 'bg-maint-pm3/20 text-maint-pm3',
  OVH: 'bg-maint-overhaul/20 text-maint-overhaul',
};

// Maintenance type descriptions
const typeDescriptions: Record<string, string> = {
  PM1: 'Preventive Maintenance Level 1',
  PM2: 'Preventive Maintenance Level 2',
  HM: 'Heavy Maintenance',
  OVH: 'Overhaul',
};

interface AlertItemProps {
  alert: MaintenanceAlert;
  onClick?: () => void;
}

/**
 * Individual Alert Item
 */
function AlertItem({ alert, onClick }: AlertItemProps) {
  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-GB', {
      day: '2-digit',
      month: 'short',
    });
  };

  return (
    <div
      className="flex items-center justify-between py-3 px-4 hover:bg-hover cursor-pointer transition-colors border-b border-border last:border-b-0"
      onClick={onClick}
      role="button"
      tabIndex={0}
    >
      <div className="flex items-center space-x-3">
        <span
          className={`px-2 py-1 text-xs font-medium rounded ${typeColors[alert.type] || 'bg-elevated text-text-secondary'}`}
          title={typeDescriptions[alert.type]}
        >
          {alert.type}
        </span>
        <div>
          <div className="font-medium text-text-primary">{alert.trainId}</div>
          <div className="text-sm text-text-muted">
            {alert.depot} ({alert.depotCode})
          </div>
        </div>
      </div>
      <div className="text-right">
        <div className="text-sm font-medium text-text-primary">
          {formatDate(alert.date)}
        </div>
        <div className="text-xs text-text-muted">
          {alert.durationDays} {alert.durationDays === 1 ? 'day' : 'days'}
        </div>
      </div>
    </div>
  );
}

/**
 * Maintenance Alerts Component
 *
 * Displays upcoming maintenance events in the next 7 days
 * with counts by type and a list of upcoming events.
 */
export function MaintenanceAlerts() {
  const router = useRouter();
  const [data, setData] = useState<MaintenanceAlertsResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchAlerts() {
      setLoading(true);
      const { data, error } = await dashboardApi.getMaintenanceAlerts();

      if (error) {
        setError(error);
      } else if (data) {
        setData(data);
      }
      setLoading(false);
    }

    fetchAlerts();
  }, []);

  const handleAlertClick = (_alertId: string) => {
    router.push('/maintenance');
  };

  const handleViewAll = () => {
    router.push('/maintenance');
  };

  if (loading) {
    return (
      <div className="bg-panel rounded-lg overflow-hidden animate-pulse border border-border">
        <div className="p-4 border-b border-border">
          <div className="h-5 bg-elevated rounded w-1/3 mb-2"></div>
          <div className="flex space-x-2">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="h-6 bg-elevated rounded w-12"></div>
            ))}
          </div>
        </div>
        {[...Array(3)].map((_, i) => (
          <div key={i} className="p-4 border-b border-border">
            <div className="h-4 bg-elevated rounded w-2/3 mb-2"></div>
            <div className="h-3 bg-elevated rounded w-1/2"></div>
          </div>
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-900/20 border border-red-800 rounded-lg p-4">
        <p className="text-red-400">
          <strong>Error loading maintenance alerts:</strong> {error}
        </p>
      </div>
    );
  }

  if (!data || data.totalUpcoming === 0) {
    return (
      <div className="bg-maint-pm1/10 border border-maint-pm1/30 rounded-lg p-6">
        <div className="flex items-center">
          <svg className="w-5 h-5 text-maint-pm1 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
          <span className="text-maint-pm1 font-medium">
            No scheduled maintenance in the next 7 days
          </span>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-panel rounded-lg overflow-hidden border border-border">
      {/* Summary Header */}
      <div className="p-4 border-b border-border bg-elevated">
        <div className="flex items-center justify-between mb-3">
          <h3 className="font-semibold text-text-primary">
            Upcoming Maintenance
          </h3>
          <span className="text-sm text-text-secondary">
            {data.totalUpcoming} event{data.totalUpcoming !== 1 ? 's' : ''} in next 7 days
          </span>
        </div>

        {/* Type Counts */}
        <div className="flex flex-wrap gap-2">
          {Object.entries(data.countByType).map(([type, count]) => (
            count > 0 && (
              <span
                key={type}
                className={`px-2 py-1 text-xs font-medium rounded ${typeColors[type]}`}
                title={typeDescriptions[type]}
              >
                {type}: {count}
              </span>
            )
          ))}
        </div>
      </div>

      {/* Alerts List */}
      <div>
        {data.alerts.map((alert) => (
          <AlertItem
            key={alert.id}
            alert={alert}
            onClick={() => handleAlertClick(alert.id)}
          />
        ))}
      </div>

      {/* View All Link */}
      {data.totalUpcoming > 5 && (
        <div className="p-3 bg-elevated text-center">
          <button
            className="text-sm text-primary-400 hover:text-primary-300 font-medium"
            onClick={handleViewAll}
          >
            View all {data.totalUpcoming} maintenance events →
          </button>
        </div>
      )}
    </div>
  );
}

