'use client';

import React, { useEffect, useState, useCallback } from 'react';
import dynamic from 'next/dynamic';
import { Card, Elevation, Checkbox, Button, Tag, Intent, Spinner, Callout } from '@blueprintjs/core';
import { trainsApi, depotsApi, Train, Depot } from '@/lib/api';

// Train status types
type TrainStatus = 'available' | 'in-service' | 'maintenance';

interface TrainWithStatus extends Train {
  status: TrainStatus;
}

// Status colors
const statusColors: Record<TrainStatus, string> = {
  available: '#22c55e',    // green-500
  'in-service': '#3b82f6', // blue-500
  maintenance: '#ef4444',  // red-500
};

const statusLabels: Record<TrainStatus, string> = {
  available: 'Available',
  'in-service': 'In Service',
  maintenance: 'Maintenance',
};

const statusIntents: Record<TrainStatus, Intent> = {
  available: Intent.SUCCESS,
  'in-service': Intent.PRIMARY,
  maintenance: Intent.DANGER,
};

// Dynamically import the map component to avoid SSR issues
const MapWithNoSSR = dynamic(
  () => import('./MapContent'),
  {
    ssr: false,
    loading: () => (
      <div style={{ height: 600, display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: '#f5f8fa', borderRadius: 4 }}>
        <Spinner size={32} />
      </div>
    )
  }
);

interface FleetMapProps {
  onTrainSelect?: (train: TrainWithStatus) => void;
}

/**
 * Fleet Map Component
 *
 * Displays an interactive map of Portugal showing:
 * - Train positions with status-colored markers
 * - Depot locations with capacity indicators
 */
export function FleetMap({ onTrainSelect }: FleetMapProps) {
  const [trains, setTrains] = useState<TrainWithStatus[]>([]);
  const [depots, setDepots] = useState<(Depot & { trainCount: number })[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [showDepots, setShowDepots] = useState(true);
  const [statusFilters, setStatusFilters] = useState<Record<TrainStatus, boolean>>({
    available: true,
    'in-service': true,
    maintenance: true,
  });

  const fetchData = useCallback(async () => {
    try {
      const [trainsRes, depotsRes] = await Promise.all([
        trainsApi.getAll(),
        depotsApi.getAll(),
      ]);

      if (trainsRes.error) throw new Error(trainsRes.error);
      if (depotsRes.error) throw new Error(depotsRes.error);

      // Add status to trains
      const trainsWithStatus: TrainWithStatus[] = (trainsRes.data?.trains || []).map((train) => {
        let status: TrainStatus = 'available';
        if (train.fitnessStatus === 'unfit') {
          status = 'maintenance';
        }
        return { ...train, status };
      });

      setTrains(trainsWithStatus);
      setDepots(depotsRes.data?.depots || []);
      setLastUpdated(new Date());
      setError(null);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load map data');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // Auto-refresh every 30 seconds
  useEffect(() => {
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, [fetchData]);

  const toggleStatusFilter = (status: TrainStatus) => {
    setStatusFilters((prev) => ({ ...prev, [status]: !prev[status] }));
  };

  const filteredTrains = trains.filter((train) => statusFilters[train.status]);

  if (loading) {
    return (
      <div style={{ height: 600, display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: '#f5f8fa', borderRadius: 4 }}>
        <Spinner size={32} />
      </div>
    );
  }

  if (error) {
    return (
      <Callout intent={Intent.DANGER} title="Error">
        {error}
      </Callout>
    );
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      {/* Controls */}
      <Card elevation={Elevation.ONE} style={{ padding: 16 }}>
        <div style={{ display: 'flex', flexWrap: 'wrap', alignItems: 'center', justifyContent: 'space-between', gap: 16 }}>
          {/* Status Filters */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <span style={{ fontSize: 14, fontWeight: 500, color: '#5c7080' }}>Filter:</span>
            {(Object.keys(statusFilters) as TrainStatus[]).map((status) => (
              <Checkbox
                key={status}
                checked={statusFilters[status]}
                onChange={() => toggleStatusFilter(status)}
                style={{ marginBottom: 0 }}
              >
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <span
                    style={{
                      width: 12,
                      height: 12,
                      borderRadius: '50%',
                      backgroundColor: statusColors[status],
                    }}
                  />
                  <span style={{ fontSize: 14 }}>{statusLabels[status]}</span>
                </div>
              </Checkbox>
            ))}
          </div>

          {/* Depot Toggle */}
          <Checkbox
            checked={showDepots}
            onChange={(e) => setShowDepots((e.target as HTMLInputElement).checked)}
            style={{ marginBottom: 0 }}
          >
            Show Depots
          </Checkbox>

          {/* Refresh */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            {lastUpdated && (
              <span style={{ fontSize: 12, color: '#5c7080' }}>
                Last updated: {lastUpdated.toLocaleTimeString()}
              </span>
            )}
            <Button
              icon="refresh"
              intent={Intent.PRIMARY}
              minimal
              onClick={fetchData}
            >
              Refresh
            </Button>
          </div>
        </div>
      </Card>

      {/* Map */}
      <MapWithNoSSR
        trains={filteredTrains}
        depots={showDepots ? depots : []}
        onTrainSelect={onTrainSelect}
        statusColors={statusColors}
        statusLabels={statusLabels}
      />

      {/* Legend */}
      <Card elevation={Elevation.ONE} style={{ padding: 12 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 24, fontSize: 14 }}>
          <span style={{ fontWeight: 500, color: '#5c7080' }}>Legend:</span>
          {(Object.keys(statusColors) as TrainStatus[]).map((status) => (
            <div key={status} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <span
                style={{
                  width: 16,
                  height: 16,
                  borderRadius: '50%',
                  backgroundColor: statusColors[status],
                }}
              />
              <span>{statusLabels[status]}</span>
            </div>
          ))}
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ width: 16, height: 16, borderRadius: 4, backgroundColor: '#6b7280' }} />
            <span>Depot</span>
          </div>
        </div>
      </Card>
    </div>
  );
}

