  statusColors: Record<TrainStatus, string>;
  statusLabels: Record<TrainStatus, string>;
}

/**
 * Map Content Component
 *
 * Uses vanilla Leaflet for better compatibility.
 */
export default function MapContent({
  trains,
  depots,
  onTrainSelect,
  statusColors,
  statusLabels,
}: MapContentProps) {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);

  useEffect(() => {
    if (!mapRef.current || mapInstanceRef.current) return;

    // Portugal center coordinates
    const portugalCenter: L.LatLngExpression = [39.5, -8.0];

    // Initialize map
    const map = L.map(mapRef.current).setView(portugalCenter, 7);
    mapInstanceRef.current = map;

    // Add tile layer
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
    }).addTo(map);

    return () => {
      map.remove();
      mapInstanceRef.current = null;
    };
  }, []);

