              <span style="font-weight: 500;">${train.baseDepot?.code || 'N/A'}</span>
            </div>
          </div>
        </div>
      `;

      marker.bindPopup(popupContent);
      marker.on('click', () => onTrainSelect?.(train));
    });

    // Add depot markers
    depots.forEach((depot) => {
