      marker.bindPopup(popupContent);
    });
  }, [trains, depots, statusColors, statusLabels, onTrainSelect]);

  return (
    <div
      ref={mapRef}
      className="h-[600px] rounded-lg overflow-hidden shadow"
      style={{ zIndex: 0 }}
    />
  );
}

