'use client';

import React, { useEffect, useState, useCallback } from 'react';
import {
  servicesApi,
  allocationsApi,
  Service,
  Recommendation,
} from '@/lib/api';

interface AllocationPanelProps {
  onAllocationComplete?: () => void;
}

/**
 * Allocation Panel Component
 *
 * Main component for train-to-service allocation:
 * - Lists pending services
 * - Generates recommendations
 * - Displays justifications
 * - Confirms allocations
 */
export function AllocationPanel({ onAllocationComplete }: AllocationPanelProps) {
  const [services, setServices] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<Service | null>(null);
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [loading, setLoading] = useState(true);
  const [recommending, setRecommending] = useState(false);
  const [allocating, setAllocating] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [selectedDate, setSelectedDate] = useState(
    new Date().toISOString().split('T')[0]
  );
  const [isFallback, setIsFallback] = useState(false);
  const [solverTime, setSolverTime] = useState(0);

  const fetchServices = useCallback(async () => {
    setLoading(true);
    setError(null);
    const { data, error } = await servicesApi.getPending(selectedDate);

    if (error) {
      setError(error);
    } else if (data) {
      setServices(data.services);
    }
    setLoading(false);
  }, [selectedDate]);

  useEffect(() => {
    fetchServices();
  }, [fetchServices]);

  const handleSelectService = (service: Service) => {
    setSelectedService(service);
    setRecommendations([]);
    setSuccessMessage(null);
  };

  const handleGetRecommendations = async () => {
    if (!selectedService) return;

    setRecommending(true);
    setError(null);

    const { data, error } = await allocationsApi.recommend(
      selectedService.id,
      selectedDate
    );

    if (error) {
      setError(error);
    } else if (data) {
      setRecommendations(data.recommendations);
      setIsFallback(data.fallback || false);
      setSolverTime(data.solverTimeMs);
    }
    setRecommending(false);
  };

  const handleAllocate = async (rec: Recommendation) => {
    if (!selectedService) return;

    setAllocating(rec.trainId);
    setError(null);

    const { data, error } = await allocationsApi.create(
      selectedService.id,
      rec.trainId,
      selectedDate,
      rec.score,
      rec.justifications
    );

    if (error) {
      setError(error);
    } else if (data) {
      setSuccessMessage(
        `Train ${rec.train_id} assigned to ${selectedService.serviceCode}`
      );
      // Remove allocated service from list
      setServices((prev) =>
        prev.filter((s) => s.id !== selectedService.id)
      );
      setSelectedService(null);
      setRecommendations([]);
      onAllocationComplete?.();
    }
    setAllocating(null);
  };

  const formatTime = (time: string | undefined) => {
    if (!time) return '--:--';
    return time.substring(0, 5);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      {/* Left Panel - Pending Services */}
      <div className="bg-panel rounded-lg overflow-hidden border border-border">
        <div className="p-4 border-b border-border bg-elevated">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-semibold text-text-primary">
              Pending Services
            </h2>
            <input
              type="date"
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
              className="px-3 py-1 border border-border bg-elevated text-text-primary rounded text-sm"
            />
          </div>
          <p className="mt-1 text-sm text-text-muted">
            {services.length} services awaiting allocation
          </p>
        </div>

        {loading ? (
          <div className="p-8 text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-500 mx-auto"></div>
            <p className="mt-2 text-text-muted">Loading services...</p>
          </div>
        ) : services.length === 0 ? (
          <div className="p-8 text-center text-text-muted">
            No pending services for {selectedDate}
          </div>
        ) : (
          <div className="divide-y divide-border max-h-[500px] overflow-y-auto">
            {services.map((service) => (
              <div
                key={service.id}
                className={`p-4 cursor-pointer transition-colors ${
                  selectedService?.id === service.id
                    ? 'bg-primary-600/20 border-l-4 border-primary-500'
                    : 'hover:bg-hover'
                }`}
                onClick={() => handleSelectService(service)}
              >
                <div className="flex items-center justify-between">
                  <span className="font-mono font-semibold text-text-primary">
                    {service.serviceCode}
                  </span>
                  <span className="text-sm text-text-muted">
                    {formatTime(service.departureTime)}
                  </span>
                </div>
                <div className="mt-1 text-sm text-text-secondary">
                  {service.origin} → {service.destination}
                </div>
                <div className="mt-1 flex items-center gap-4 text-xs text-text-muted">
                  <span>{service.distanceKm} km</span>
                  <span className="capitalize">{service.serviceType}</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Right Panel - Recommendations */}
      <div className="bg-panel rounded-lg overflow-hidden border border-border">
        <div className="p-4 border-b border-border bg-elevated">
          <h2 className="text-lg font-semibold text-text-primary">
            Train Recommendations
          </h2>
          {selectedService && (
            <p className="mt-1 text-sm text-text-secondary">
              For {selectedService.serviceCode}: {selectedService.origin} →{' '}
              {selectedService.destination}
            </p>
          )}
        </div>

        {/* Success Message */}
        {successMessage && (
          <div className="p-4 bg-maint-pm1/10 border-b border-maint-pm1/30">
            <div className="flex items-center">
              <svg className="w-5 h-5 text-maint-pm1 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
              <span className="text-maint-pm1">{successMessage}</span>
            </div>
          </div>
        )}

        {/* Error Message */}
        {error && (
          <div className="p-4 bg-red-900/20 border-b border-red-800">
            <p className="text-red-400">{error}</p>
          </div>
        )}

        {!selectedService ? (
          <div className="p-8 text-center text-text-muted">
            Select a service to get train recommendations
          </div>
        ) : recommendations.length === 0 ? (
          <div className="p-8 text-center">
            <button
              onClick={handleGetRecommendations}
              disabled={recommending}
              className="px-6 py-3 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              {recommending ? (
                <span className="flex items-center">
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                  Analyzing...
                </span>
              ) : (
                'Get Recommendations'
              )}
            </button>
            <p className="mt-2 text-sm text-text-muted">
              AI-powered recommendations based on km balancing
            </p>
          </div>
        ) : (
          <div>
            {/* Solver Info */}
            {isFallback && (
              <div className="p-3 bg-amber-500/10 border-b border-amber-500/30">
                <p className="text-sm text-amber-400">
                  Using fallback ranking (solver unavailable)
                </p>
              </div>
            )}
            {solverTime > 0 && (
              <div className="p-2 bg-elevated border-b border-border text-xs text-text-muted text-right">
                Solver time: {solverTime}ms
              </div>
            )}

            {/* Recommendations List */}
            <div className="divide-y divide-border">
              {recommendations.map((rec, idx) => (
                <div key={rec.trainId} className="p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <span className="font-mono font-semibold text-text-primary">
                        {rec.train_id}
                      </span>
                      <span className="ml-2 px-2 py-0.5 text-xs rounded bg-primary-600/20 text-primary-400">
                        Score: {rec.score}
                      </span>
                      {idx === 0 && (
                        <span className="ml-2 px-2 py-0.5 text-xs rounded bg-maint-pm1/20 text-maint-pm1">
                          Best Match
                        </span>
                      )}
                    </div>
                    <button
                      onClick={() => handleAllocate(rec)}
                      disabled={allocating !== null}
                      className="px-4 py-2 bg-maint-pm1 text-white rounded hover:bg-maint-pm1/80 disabled:opacity-50 disabled:cursor-not-allowed text-sm transition-colors"
                    >
                      {allocating === rec.trainId ? 'Assigning...' : 'Assign'}
                    </button>
                  </div>

                  <div className="mt-2 text-sm text-text-secondary">
                    Dead running: {rec.deadRunningKm} km
                  </div>

                  {/* Justifications */}
                  <div className="mt-3 space-y-1">
                    {rec.justifications.map((j, jIdx) => (
                      <div
                        key={jIdx}
                        className="flex items-start text-sm text-text-secondary"
                      >
                        <span className="text-maint-pm1 mr-2">✓</span>
                        <span>{j}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

