    37→
    38→/**
    39→ * Simulation Panel Component
    40→ *
    41→ * Enables what-if scenario creation and comparison.
    42→ */
    43→export function SimulationPanel() {
    44→  const [scenarios, setScenarios] = useState<Scenario[]>([]);
    45→  const [selectedScenario, setSelectedScenario] = useState<Scenario | null>(null);
    46→  const [simulationResult, setSimulationResult] = useState<SimulationResult | null>(null);
    47→  const [creating, setCreating] = useState(false);
    48→  const [running, setRunning] = useState(false);
    49→  const [newScenarioName, setNewScenarioName] = useState('');
    50→  const [error, setError] = useState<string | null>(null);
    51→
    52→  // Allocation Editor state
    53→  const [pendingServices, setPendingServices] = useState<Service[]>([]);
    54→  const [availableTrains, setAvailableTrains] = useState<Train[]>([]);
    55→  const [allocationChanges, setAllocationChanges] = useState<AllocationChange[]>([]);
    56→  const [loadingServices, setLoadingServices] = useState(false);
    57→
    58→  // Multi-scenario comparison state (Issue #7 fix)
    59→  const [selectedForComparison, setSelectedForComparison] = useState<Set<string>>(new Set());
    60→  const [comparisonResults, setComparisonResults] = useState<Map<string, SimulationResult>>(new Map());
    61→  const [comparing, setComparing] = useState(false);
    62→
    63→  // Apply to Live state
    64→  const [showApplyConfirm, setShowApplyConfirm] = useState(false);
    65→  const [applying, setApplying] = useState(false);
    66→
    67→  // Fetch services and trains when a scenario is selected
    68→  useEffect(() => {
    69→    if (selectedScenario) {
    70→      loadServicesAndTrains();
    71→    }
    72→  }, [selectedScenario]);
    73→
    74→  const loadServicesAndTrains = async () => {
    75→    setLoadingServices(true);
    76→    setError(null);
    77→
    78→    const [servicesResult, trainsResult] = await Promise.all([
    79→      servicesApi.getPending(),
    80→      trainsApi.getAll({ status: 'fit' }),
    81→    ]);
    82→
    83→    if (servicesResult.error) {
    84→      setError(servicesResult.error);
    85→    } else if (servicesResult.data) {
    86→      setPendingServices(servicesResult.data.services);
    87→    }
    88→
    89→    if (trainsResult.error) {
    90→      setError(trainsResult.error);
    91→    } else if (trainsResult.data) {
    92→      setAvailableTrains(trainsResult.data.trains);
    93→    }
    94→
    95→    setLoadingServices(false);
    96→  };
    97→
    98→  const handleTrainChange = (service: Service, newTrainId: string) => {
    99→    setAllocationChanges((prev) => {
   100→      // Remove existing change for this service if any
   101→      const filtered = prev.filter((c) => c.serviceId !== service.id);
   102→
   103→      if (!newTrainId) {
   104→        // If no train selected, just remove the change
   105→        return filtered;
   106→      }
   107→
   108→      // Add new change
   109→      return [
   110→        ...filtered,
   111→        {
   112→          serviceId: service.id,
   113→          serviceCode: service.serviceCode,
   114→          origin: service.origin,
   115→          destination: service.destination,
   116→          originalTrainId: null, // No current allocation for pending services
   117→          newTrainId,
   118→        },
   119→      ];
   120→    });
   121→
   122→    // Update scenario change count
   123→    if (selectedScenario) {
   124→      setScenarios((prev) =>
   125→        prev.map((s) =>
   126→          s.id === selectedScenario.id
   127→            ? { ...s, changeCount: allocationChanges.length + 1 }
   128→            : s
   129→        )
   130→      );
   131→    }
   132→  };
   133→
   134→  const getSelectedTrainForService = (serviceId: string): string => {
   135→    const change = allocationChanges.find((c) => c.serviceId === serviceId);
   136→    return change?.newTrainId || '';
   137→  };
   138→
   139→  const removeAllocationChange = (serviceId: string) => {
   140→    setAllocationChanges((prev) => prev.filter((c) => c.serviceId !== serviceId));
   141→  };
   142→
   143→  // Toggle scenario selection for comparison
   144→  const toggleComparisonSelection = (scenarioId: string) => {
   145→    setSelectedForComparison((prev) => {
   146→      const next = new Set(prev);
   147→      if (next.has(scenarioId)) {
   148→        next.delete(scenarioId);
   149→      } else if (next.size < 3) {
   150→        // Max 3 scenarios for comparison
   151→        next.add(scenarioId);
   152→      }
   153→      return next;
   154→    });
   155→  };
   156→
   157→  // Run comparison for selected scenarios
   158→  const handleCompareScenarios = async () => {
   159→    if (selectedForComparison.size < 2) {
   160→      setError('Select at least 2 scenarios to compare');
   161→      return;
   162→    }
   163→
   164→    setComparing(true);
   165→    setError(null);
   166→    const results = new Map<string, SimulationResult>();
   167→
   168→    for (const scenarioId of Array.from(selectedForComparison)) {
   169→      const scenario = scenarios.find((s) => s.id === scenarioId);
   170→      if (!scenario || scenario.changeCount === 0) continue;
   171→
   172→      const { data, error: compError } = await apiFetch<SimulationResult>(
   173→        `/api/simulation/${scenarioId}/run`,
   174→        {
   175→          method: 'POST',
   176→          body: JSON.stringify({
   177→            changes: [], // Use stored changes from scenario
   178→          }),
   179→        }
   180→      );
   181→
   182→      if (data) {
   183→        results.set(scenarioId, data);
   184→      }
   185→    }
   186→
   187→    setComparisonResults(results);
   188→    setComparing(false);
   189→  };
   190→
   191→  // Apply scenario changes to live allocations
   192→  const handleApplyToLive = async () => {
   193→    if (!selectedScenario || allocationChanges.length === 0) return;
   194→
   195→    setApplying(true);
   196→    setError(null);
   197→
   198→    const { data, error: applyError } = await apiFetch<{ applied: number }>(
   199→      `/api/simulation/${selectedScenario.id}/apply`,
   200→      {
   201→        method: 'POST',
   202→        body: JSON.stringify({
   203→          changes: allocationChanges.map((change) => ({
   204→            serviceId: change.serviceId,
   205→            trainId: change.newTrainId,
   206→          })),
   207→        }),
   208→      }
   209→    );
   210→
   211→    if (applyError) {
   212→      setError(applyError);
   213→    } else if (data) {
   214→      // Clear the scenario after applying
   215→      setAllocationChanges([]);
   216→      setSimulationResult(null);
   217→      setShowApplyConfirm(false);
   218→
   219→      // Remove the applied scenario from list
   220→      setScenarios((prev) => prev.filter((s) => s.id !== selectedScenario.id));
   221→      setSelectedScenario(null);
   222→    }
   223→
   224→    setApplying(false);
   225→  };
   226→
   227→  const handleCreateScenario = async () => {
   228→    if (!newScenarioName.trim()) return;
   229→
   230→    setCreating(true);
   231→    setError(null);
   232→
   233→    const { data, error } = await apiFetch<{ scenarioId: string } & Scenario>(
   234→      '/api/simulation/create',
   235→      {
   236→        method: 'POST',
   237→        body: JSON.stringify({
   238→          name: newScenarioName,
   239→          baseDate: new Date().toISOString().split('T')[0],
   240→        }),
   241→      }
   242→    );
   243→
   244→    if (error) {
   245→      setError(error);
   246→    } else if (data) {
   247→      const newScenario: Scenario = {
   248→        id: data.scenarioId,
   249→        name: newScenarioName,
   250→        baseDate: new Date().toISOString().split('T')[0],
   251→        changeCount: 0,
   252→        createdAt: new Date().toISOString(),
   253→      };
   254→      setScenarios((prev) => [...prev, newScenario]);
   255→      setSelectedScenario(newScenario);
   256→      setNewScenarioName('');
   257→    }
   258→
   259→    setCreating(false);
   260→  };
   261→
   262→  const handleRunSimulation = async () => {
   263→    if (!selectedScenario) return;
   264→
   265→    if (allocationChanges.length === 0) {
   266→      setError('Please assign at least one train to a service before running simulation');
   267→      return;
   268→    }
   269→
   270→    setRunning(true);
   271→    setError(null);
   272→
   273→    // Run simulation with actual user-defined changes
   274→    const { data, error: simError } = await apiFetch<SimulationResult>(
   275→      `/api/simulation/${selectedScenario.id}/run`,
   276→      {
   277→        method: 'POST',
   278→        body: JSON.stringify({
   279→          changes: allocationChanges.map((change) => ({
   280→            serviceId: change.serviceId,
   281→            originalTrainId: change.originalTrainId,
   282→            newTrainId: change.newTrainId,
   283→          })),
   284→        }),
   285→      }
   286→    );
   287→
   288→    if (simError) {
   289→      setError(simError);
   290→    } else if (data) {
   291→      setSimulationResult(data);
   292→    }
   293→
   294→    setRunning(false);
   295→  };
   296→
   297→  return (
   298→    <div className="space-y-6">
