   360→                }`}
   361→              >
   362→                <div className="flex items-center gap-4">
   363→                  {/* Checkbox for comparison */}
   364→                  <input
   365→                    type="checkbox"
   366→                    checked={selectedForComparison.has(scenario.id)}
   367→                    onChange={() => toggleComparisonSelection(scenario.id)}
   368→                    className="w-4 h-4 text-purple-600 rounded focus:ring-purple-500"
   369→                    title="Select for comparison"
   370→                  />
   371→
   372→                  {/* Scenario info - clickable for editing */}
   373→                  <div
   374→                    className="flex-1 cursor-pointer"
   375→                    onClick={() => setSelectedScenario(scenario)}
