   377→                    <div className="font-medium text-gray-900">{scenario.name}</div>
   378→                    <div className="text-sm text-gray-500">
   379→                      Base: {scenario.baseDate} • Changes: {scenario.changeCount}
   380→                    </div>
   381→                  </div>
   382→
   383→                  {/* Actions */}
   384→                  {selectedScenario?.id === scenario.id && (
