   392→                    >
   393→                      {running ? 'Running...' : 'Run Simulation'}
   394→                    </button>
   395→                  )}
   396→                </div>
   397→              </div>
   398→            ))}
   399→          </div>
   400→        </div>
   401→      )}
   402→
   403→      {/* Allocation Editor - Issue #6 Fix */}
   404→      {selectedScenario && (
   405→        <div className="bg-white shadow rounded-lg overflow-hidden">
   406→          <div className="p-4 border-b border-gray-200 bg-blue-50">
   407→            <h3 className="font-semibold text-blue-800">
