   648→          </div>
   649→        </div>
   650→      )}
   651→
   652→      {/* Multi-Scenario Comparison Results (Issue #7 Fix) */}
   653→      {comparisonResults.size >= 2 && (
   654→        <div className="bg-white shadow rounded-lg overflow-hidden">
   655→          <div className="p-4 border-b border-gray-200 bg-purple-50">
   656→            <h3 className="font-semibold text-purple-800">
   657→              Scenario Comparison ({comparisonResults.size} scenarios)
   658→            </h3>
   659→            <p className="text-sm text-purple-600">
   660→              Side-by-side comparison of selected scenarios
   661→            </p>
   662→          </div>
   663→
   664→          <div className="overflow-x-auto">
   665→            <table className="w-full">
   666→              <thead className="bg-gray-50">
   667→                <tr>
   668→                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
   669→                    Metric
