'use client';

import React, { useEffect, useState, useCallback } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  ReferenceLine,
  Cell,
} from 'recharts';
import { Card, Elevation, Spinner, Callout, Intent, Tag } from '@blueprintjs/core';
import { apiFetch } from '@/lib/api';

interface DistributionBucket {
  kmRange: string;
  count: number;
}

interface Outlier {
  trainId: string;
  currentKm: number;
  delta: number;
  deltaPercent: number;
  status: 'over' | 'under';
}

interface DistributionResponse {
  average: number;
  variance: number;
  distribution: DistributionBucket[];
  outliers: Outlier[];
}

interface RankedTrain {
  id: string;
  trainId: string;
  fleetName: string;
  depotCode: string;
  currentKm: number;
  targetKm: number;
  delta: number;
  deltaPercent: number;
  status: 'over' | 'under' | 'balanced';
}

interface RankingResponse {
  average: number;
  trains: RankedTrain[];
}

/**
 * Balancing Dashboard Component
 *
 * Displays mileage distribution, train ranking, and outlier identification.
 */
export function BalancingDashboard() {
  const [distribution, setDistribution] = useState<DistributionResponse | null>(null);
  const [ranking, setRanking] = useState<RankingResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);

    const [distRes, rankRes] = await Promise.all([
      apiFetch<DistributionResponse>('/api/balancing/distribution'),
      apiFetch<RankingResponse>('/api/balancing/ranking'),
    ]);

    if (distRes.error) {
      setError(distRes.error);
    } else {
      setDistribution(distRes.data);
    }

    if (rankRes.error && !error) {
      setError(rankRes.error);
    } else {
      setRanking(rankRes.data);
    }

    setLoading(false);
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', padding: 48 }}>
        <Spinner size={32} />
      </div>
    );
  }

  if (error) {
    return (
      <Callout intent={Intent.DANGER} title="Error">
        {error}
      </Callout>
    );
  }

  // Prepare data for chart
  const chartData = distribution?.distribution.map((d, idx) => ({
    ...d,
    fill: idx === 4 || idx === 5 ? '#22c55e' : '#94a3b8', // Highlight middle buckets
  })) || [];

  // Top 5 over and under running trains
  const topOver = ranking?.trains.filter(t => t.status === 'over').slice(0, 5) || [];
  const topUnder = ranking?.trains.filter(t => t.status === 'under').slice(0, 5) || [];

  // Determine variance intent
  const getVarianceIntent = (variance: number): Intent => {
    if (variance <= 10) return Intent.SUCCESS;
    if (variance <= 20) return Intent.WARNING;
    return Intent.DANGER;
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
      {/* Summary Stats */}
      <div className="mms-grid-3">
        <Card elevation={Elevation.ONE} style={{ padding: 16 }}>
          <div style={{ fontSize: 14, fontWeight: 500, color: '#5c7080' }}>Fleet Average</div>
          <div style={{ fontSize: 28, fontWeight: 700, color: '#182026' }}>
            {distribution?.average.toLocaleString()} km
          </div>
        </Card>
        <Card elevation={Elevation.ONE} style={{ padding: 16 }}>
          <div style={{ fontSize: 14, fontWeight: 500, color: '#5c7080' }}>Variance</div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 4 }}>
            <Tag large intent={getVarianceIntent(distribution?.variance || 0)}>
              {distribution?.variance}%
            </Tag>
          </div>
        </Card>
        <Card elevation={Elevation.ONE} style={{ padding: 16 }}>
          <div style={{ fontSize: 14, fontWeight: 500, color: '#5c7080' }}>Outliers ({'>'} 15% deviation)</div>
          <div style={{ fontSize: 28, fontWeight: 700, color: '#db3737' }}>
            {distribution?.outliers.length || 0} trains
          </div>
        </Card>
      </div>

      {/* Distribution Chart */}
      <Card elevation={Elevation.ONE} style={{ padding: 24 }}>
        <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 600, color: '#182026' }}>
          Mileage Distribution
        </h2>
        <div style={{ height: 256 }}>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis
                dataKey="kmRange"
                fontSize={10}
                angle={-45}
                textAnchor="end"
                height={60}
              />
              <YAxis />
              <Tooltip />
              <ReferenceLine
                x={4}
                stroke="#22c55e"
                strokeWidth={2}
                label={{ value: 'Target', position: 'top', fill: '#22c55e' }}
              />
              <Bar dataKey="count" name="Trains">
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.fill} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
        <p style={{ marginTop: 8, fontSize: 14, color: '#5c7080', textAlign: 'center' }}>
          Green bars indicate target mileage range (±10% of average)
        </p>
      </Card>

      {/* Train Ranking */}
      <div className="mms-grid-2">
        {/* Over-Running Trains */}
        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#fef2f2' }}>
            <h3 style={{ margin: 0, fontWeight: 600, color: '#991b1b' }}>
              Over-Running Trains (Top 5)
            </h3>
            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#dc2626' }}>
              These trains have higher than average mileage
            </p>
          </div>
          <div>
            {topOver.length === 0 ? (
              <div style={{ padding: 16, textAlign: 'center', color: '#5c7080' }}>
                No over-running trains
              </div>
            ) : (
              topOver.map((train) => (
                <div key={train.id} style={{ padding: 16, borderBottom: '1px solid #f3f4f6', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                  <div>
                    <div className="train-id" style={{ fontWeight: 600, color: '#182026' }}>
                      {train.trainId}
                    </div>
                    <div style={{ fontSize: 14, color: '#5c7080' }}>
                      {train.fleetName} • {train.depotCode}
                    </div>
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: 18, fontWeight: 600, color: '#dc2626' }}>
                      +{train.deltaPercent}%
                    </div>
                    <div style={{ fontSize: 14, color: '#5c7080' }}>
                      {train.currentKm.toLocaleString()} km
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </Card>

        {/* Under-Running Trains */}
        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#eff6ff' }}>
            <h3 style={{ margin: 0, fontWeight: 600, color: '#1e40af' }}>
              Under-Running Trains (Top 5)
            </h3>
            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#3b82f6' }}>
              Priority candidates for allocation
            </p>
          </div>
          <div>
            {topUnder.length === 0 ? (
              <div style={{ padding: 16, textAlign: 'center', color: '#5c7080' }}>
                No under-running trains
              </div>
            ) : (
              topUnder.map((train) => (
                <div key={train.id} style={{ padding: 16, borderBottom: '1px solid #f3f4f6', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                  <div>
                    <div className="train-id" style={{ fontWeight: 600, color: '#182026' }}>
                      {train.trainId}
                    </div>
                    <div style={{ fontSize: 14, color: '#5c7080' }}>
                      {train.fleetName} • {train.depotCode}
                    </div>
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: 18, fontWeight: 600, color: '#3b82f6' }}>
                      {train.deltaPercent}%
                    </div>
                    <div style={{ fontSize: 14, color: '#5c7080' }}>
                      {train.currentKm.toLocaleString()} km
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </Card>
      </div>

      {/* Outliers Alert */}
      {distribution && distribution.outliers.length > 0 && (
        <Callout intent={Intent.WARNING} icon="warning-sign" title={`Outlier Trains (${distribution.outliers.length})`}>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginTop: 8 }}>
            {distribution.outliers.slice(0, 10).map((o) => (
              <Tag
                key={o.trainId}
                intent={o.status === 'over' ? Intent.DANGER : Intent.PRIMARY}
                minimal
              >
                {o.trainId}: {o.deltaPercent > 0 ? '+' : ''}{o.deltaPercent}%
              </Tag>
            ))}
            {distribution.outliers.length > 10 && (
              <span style={{ fontSize: 14, color: '#5c7080' }}>
                +{distribution.outliers.length - 10} more
              </span>
            )}
          </div>
        </Callout>
      )}
    </div>
  );
}

