          </p>
          <Callout intent={Intent.WARNING} style={{ marginTop: 16 }}>
            <strong>Changes to apply:</strong>
            <ul style={{ marginTop: 8, paddingLeft: 20 }}>
              {allocationChanges.slice(0, 5).map((change) => (
                <li key={change.serviceId}>
                  {change.serviceCode}: Assign train {change.newTrainId.slice(0, 8)}...
                </li>
              ))}
              {allocationChanges.length > 5 && (
                <li>... and {allocationChanges.length - 5} more</li>
              )}
            </ul>
          </Callout>
        </div>
        <div className={Classes.DIALOG_FOOTER}>
          <div className={Classes.DIALOG_FOOTER_ACTIONS}>
            <Button onClick={() => setShowApplyConfirm(false)}>Cancel</Button>
            <Button
              onClick={handleApplyToLive}
              disabled={applying}
              intent={Intent.PRIMARY}
              loading={applying}
            >
              Confirm Apply
            </Button>
          </div>
        </div>
      </Dialog>

      {/* Multi-Scenario Comparison Results */}
      {comparisonResults.size >= 2 && (
        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#ede9fe' }}>
            <h3 style={{ margin: 0, fontWeight: 600, color: '#5b21b6' }}>
              Scenario Comparison ({comparisonResults.size} scenarios)
            </h3>
            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#7c3aed' }}>
              Side-by-side comparison of selected scenarios
            </p>
          </div>

          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead style={{ backgroundColor: '#f5f8fa' }}>
                <tr>
                  <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Metric</th>
                  {Array.from(comparisonResults.keys()).map((scenarioId) => {
                    const scenario = scenarios.find((s) => s.id === scenarioId);
                    return (
                      <th key={scenarioId} style={{ padding: 12, textAlign: 'center', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>
                        {scenario?.name || 'Scenario'}
                      </th>
                    );
                  })}
                </tr>
              </thead>
              <tbody>
                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Projected Variance</td>
                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedVariance);
                    const isBest = result.projectedVariance === Math.min(...allValues);
                    return (
                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
                        {result.projectedVariance}%{isBest && ' ✓'}
                      </td>
                    );
                  })}
                </tr>
                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Dead Running</td>
                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedDeadRunning);
                    const isBest = result.projectedDeadRunning === Math.min(...allValues);
                    return (
                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
                        {result.projectedDeadRunning} km{isBest && ' ✓'}
                      </td>
                    );
                  })}
                </tr>
              </tbody>
            </table>
          </div>

          <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed', display: 'flex', justifyContent: 'flex-end' }}>
            <Button
              minimal
              onClick={() => {
                setComparisonResults(new Map());
                setSelectedForComparison(new Set());
              }}
            >
              Clear Comparison
            </Button>
          </div>
        </Card>
      )}

      {/* Empty State */}
      {scenarios.length === 0 && (
        <Card elevation={Elevation.ONE} style={{ padding: 48, textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🔬</div>
          <h3 style={{ margin: '0 0 8px', fontSize: 18, fontWeight: 500, color: '#182026' }}>
            No Scenarios Yet
          </h3>
          <p style={{ margin: 0, color: '#5c7080' }}>
            Create a scenario above to start testing allocation strategies
          </p>
        </Card>
      )}
    </div>
  );
}

