   331→
   332→      {/* Scenarios List */}
   333→      {scenarios.length > 0 && (
   334→        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
   335→          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#f5f8fa', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
   336→            <div>
   337→              <h3 style={{ margin: 0, fontWeight: 600, color: '#182026' }}>Your Scenarios</h3>
   338→              <p style={{ margin: '4px 0 0', fontSize: 12, color: '#5c7080' }}>Select up to 3 scenarios to compare</p>
   339→            </div>
   340→            {selectedForComparison.size >= 2 && (
   341→              <Button
   342→                onClick={handleCompareScenarios}
   343→                disabled={comparing}
   344→                intent={Intent.NONE}
   345→                loading={comparing}
   346→                style={{ backgroundColor: '#7c3aed', color: 'white' }}
   347→              >
   348→                Compare {selectedForComparison.size} Scenarios
   349→              </Button>
   350→            )}
   351→          </div>
   352→          <div>
   353→            {scenarios.map((scenario) => (
   354→              <div
   355→                key={scenario.id}
   356→                style={{
   357→                  padding: 16,
   358→                  borderBottom: '1px solid #e1e8ed',
   359→                  backgroundColor: selectedScenario?.id === scenario.id ? '#e1e8ed' : selectedForComparison.has(scenario.id) ? '#ede9fe' : 'transparent',
   360→                  borderLeft: selectedScenario?.id === scenario.id ? '4px solid #2563eb' : '4px solid transparent',
   361→                }}
   362→              >
   363→                <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
   364→                  <Checkbox
   365→                    checked={selectedForComparison.has(scenario.id)}
   366→                    onChange={() => toggleComparisonSelection(scenario.id)}
   367→                  />
   368→                  <div
   369→                    style={{ flex: 1, cursor: 'pointer' }}
   370→                    onClick={() => setSelectedScenario(scenario)}
   371→                  >
   372→                    <div style={{ fontWeight: 500, color: '#182026' }}>{scenario.name}</div>
   373→                    <div style={{ fontSize: 14, color: '#5c7080' }}>
   374→                      Base: {scenario.baseDate} • Changes: {scenario.changeCount}
   375→                    </div>
   376→                  </div>
   377→                  {selectedScenario?.id === scenario.id && (
   378→                    <Button
   379→                      onClick={(e: React.MouseEvent) => {
   380→                        e.stopPropagation();
   381→                        handleRunSimulation();
   382→                      }}
   383→                      disabled={running}
   384→                      intent={Intent.SUCCESS}
   385→                      loading={running}
   386→                      small
   387→                    >
   388→                      Run Simulation
   389→                    </Button>
   390→                  )}
   391→                </div>
   392→              </div>
   393→            ))}
   394→          </div>
   395→        </Card>
   396→      )}
   397→
   398→      {/* Allocation Editor */}
   399→      {selectedScenario && (
   400→        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
   401→          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#eff6ff' }}>
   402→            <h3 style={{ margin: 0, fontWeight: 600, color: '#1e40af' }}>
   403→              Allocation Editor: {selectedScenario.name}
   404→            </h3>
   405→            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#3b82f6' }}>
   406→              Assign trains to pending services. Changes: {allocationChanges.length}
   407→            </p>
   408→          </div>
   409→
   410→          {loadingServices ? (
   411→            <div style={{ padding: 32, textAlign: 'center' }}>
   412→              <Spinner size={24} />
   413→              <p style={{ marginTop: 8, color: '#5c7080' }}>Loading services and trains...</p>
   414→            </div>
   415→          ) : pendingServices.length === 0 ? (
   416→            <div style={{ padding: 32, textAlign: 'center', color: '#5c7080' }}>
   417→              No pending services found for today.
   418→            </div>
   419→          ) : (
   420→            <div style={{ overflowX: 'auto' }}>
   421→              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
   422→                <thead style={{ backgroundColor: '#f5f8fa' }}>
   423→                  <tr>
   424→                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Service</th>
   425→                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Route</th>
   426→                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Distance</th>
   427→                    <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Assign Train</th>
   428→                  </tr>
   429→                </thead>
   430→                <tbody>
   431→                  {pendingServices.slice(0, 10).map((service) => (
   432→                    <tr
   433→                      key={service.id}
   434→                      style={{
   435→                        borderBottom: '1px solid #e1e8ed',
   436→                        backgroundColor: getSelectedTrainForService(service.id) ? '#ecfdf5' : 'transparent',
   437→                      }}
   438→                    >
   439→                      <td style={{ padding: 12 }}>
   440→                        <div style={{ fontWeight: 500, color: '#182026' }}>{service.serviceCode}</div>
   441→                        <div style={{ fontSize: 12, color: '#5c7080' }}>{service.departureTime?.slice(0, 5) || '--:--'}</div>
   442→                      </td>
   443→                      <td style={{ padding: 12, fontSize: 14, color: '#5c7080' }}>
   444→                        {service.origin} → {service.destination}
   445→                      </td>
   446→                      <td style={{ padding: 12, fontSize: 14, color: '#5c7080' }}>
   447→                        {service.distanceKm} km
   448→                      </td>
   449→                      <td style={{ padding: 12 }}>
   450→                        <HTMLSelect
   451→                          value={getSelectedTrainForService(service.id)}
   452→                          onChange={(e) => handleTrainChange(service, e.target.value)}
   453→                          fill
   454→                        >
   455→                          <option value="">-- Select Train --</option>
   456→                          {availableTrains.map((train) => (
   457→                            <option key={train.id} value={train.id}>
   458→                              {train.trainId} ({train.currentKm.toLocaleString()} km, {train.deltaPercent > 0 ? '+' : ''}{train.deltaPercent.toFixed(1)}%)
   459→                            </option>
   460→                          ))}
   461→                        </HTMLSelect>
   462→                      </td>
   463→                    </tr>
   464→                  ))}
   465→                </tbody>
   466→              </table>
   467→            </div>
   468→          )}
   469→
   470→          {/* Summary of Changes */}
   471→          {allocationChanges.length > 0 && (
   472→            <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed' }}>
   473→              <h4 style={{ margin: '0 0 8px', fontWeight: 500, color: '#182026' }}>
   474→                Pending Changes ({allocationChanges.length})
   475→              </h4>
   476→              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
   477→                {allocationChanges.map((change) => {
   478→                  const train = availableTrains.find((t) => t.id === change.newTrainId);
   479→                  return (
   480→                    <Tag key={change.serviceId} intent={Intent.PRIMARY} minimal interactive onRemove={() => removeAllocationChange(change.serviceId)}>
   481→                      {change.serviceCode} → {train?.trainId || change.newTrainId}
   482→                    </Tag>
   483→                  );
   484→                })}
   485→              </div>
   486→            </div>
   487→          )}
   488→        </Card>
   489→      )}
   490→
   491→      {/* Simulation Results */}
   492→      {simulationResult && (
   493→        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
   494→          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#ecfdf5' }}>
   495→            <h3 style={{ margin: 0, fontWeight: 600, color: '#166534' }}>Simulation Results</h3>
   496→            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#22c55e' }}>
   497→              Projected impact of {selectedScenario?.name}
   498→            </p>
   499→          </div>
   500→
   501→          <div style={{ overflowX: 'auto' }}>
   502→            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
   503→              <thead style={{ backgroundColor: '#f5f8fa' }}>
   504→                <tr>
   505→                  <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Metric</th>
   506→                  <th style={{ padding: 12, textAlign: 'right', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Current</th>
   507→                  <th style={{ padding: 12, textAlign: 'right', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Projected</th>
   508→                  <th style={{ padding: 12, textAlign: 'right', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Change</th>
   509→                </tr>
   510→              </thead>
   511→              <tbody>
   512→                {simulationResult.comparison.map((metric) => (
   513→                  <tr key={metric.metric} style={{ borderBottom: '1px solid #e1e8ed' }}>
   514→                    <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>{metric.metric}</td>
   515→                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', color: '#5c7080' }}>{metric.current}</td>
   516→                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', fontWeight: 500, color: '#182026' }}>{metric.projected}</td>
   517→                    <td style={{ padding: 12, fontSize: 14, textAlign: 'right', fontWeight: 500, color: metric.improved ? '#22c55e' : '#dc2626' }}>
   518→                      {metric.change > 0 ? '+' : ''}{metric.change}
   519→                      {metric.improved && ' ✓'}
   520→                    </td>
   521→                  </tr>
   522→                ))}
   523→              </tbody>
   524→            </table>
   525→          </div>
   526→
   527→          <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
   528→            <div>
   529→              <span style={{ fontSize: 14, color: '#5c7080', marginRight: 16 }}>
   530→                Projected Variance: <strong>{simulationResult.projectedVariance}%</strong>
   531→              </span>
   532→              <span style={{ fontSize: 14, color: '#5c7080' }}>
   533→                Dead Running: <strong>{simulationResult.projectedDeadRunning} km</strong>
   534→              </span>
   535→            </div>
   536→            <Button
   537→              onClick={() => setShowApplyConfirm(true)}
   538→              disabled={allocationChanges.length === 0}
   539→              intent={Intent.PRIMARY}
   540→            >
   541→              Apply to Live
   542→            </Button>
   543→          </div>
   544→        </Card>
   545→      )}
   546→
   547→      {/* Apply to Live Confirmation Dialog */}
   548→      <Dialog
   549→        isOpen={showApplyConfirm}
   550→        onClose={() => setShowApplyConfirm(false)}
   551→        title="Confirm Apply to Live"
   552→      >
   553→        <div className={Classes.DIALOG_BODY}>
   554→          <p>
   555→            This will create {allocationChanges.length} new allocation(s) in the live system.
   556→            This action cannot be undone.
   557→          </p>
   558→          <Callout intent={Intent.WARNING} style={{ marginTop: 16 }}>
   559→            <strong>Changes to apply:</strong>
   560→            <ul style={{ marginTop: 8, paddingLeft: 20 }}>
   561→              {allocationChanges.slice(0, 5).map((change) => (
   562→                <li key={change.serviceId}>
   563→                  {change.serviceCode}: Assign train {change.newTrainId.slice(0, 8)}...
   564→                </li>
   565→              ))}
   566→              {allocationChanges.length > 5 && (
   567→                <li>... and {allocationChanges.length - 5} more</li>
   568→              )}
   569→            </ul>
   570→          </Callout>
   571→        </div>
   572→        <div className={Classes.DIALOG_FOOTER}>
   573→          <div className={Classes.DIALOG_FOOTER_ACTIONS}>
   574→            <Button onClick={() => setShowApplyConfirm(false)}>Cancel</Button>
   575→            <Button
   576→              onClick={handleApplyToLive}
   577→              disabled={applying}
   578→              intent={Intent.PRIMARY}
   579→              loading={applying}
   580→            >
   581→              Confirm Apply
   582→            </Button>
   583→          </div>
   584→        </div>
   585→      </Dialog>
   586→
   587→      {/* Multi-Scenario Comparison Results */}
   588→      {comparisonResults.size >= 2 && (
   589→        <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
   590→          <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', backgroundColor: '#ede9fe' }}>
   591→            <h3 style={{ margin: 0, fontWeight: 600, color: '#5b21b6' }}>
   592→              Scenario Comparison ({comparisonResults.size} scenarios)
   593→            </h3>
   594→            <p style={{ margin: '4px 0 0', fontSize: 14, color: '#7c3aed' }}>
   595→              Side-by-side comparison of selected scenarios
   596→            </p>
   597→          </div>
   598→
   599→          <div style={{ overflowX: 'auto' }}>
   600→            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
   601→              <thead style={{ backgroundColor: '#f5f8fa' }}>
   602→                <tr>
   603→                  <th style={{ padding: 12, textAlign: 'left', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>Metric</th>
   604→                  {Array.from(comparisonResults.keys()).map((scenarioId) => {
   605→                    const scenario = scenarios.find((s) => s.id === scenarioId);
   606→                    return (
   607→                      <th key={scenarioId} style={{ padding: 12, textAlign: 'center', fontSize: 12, fontWeight: 500, color: '#5c7080', textTransform: 'uppercase' }}>
   608→                        {scenario?.name || 'Scenario'}
   609→                      </th>
   610→                    );
   611→                  })}
   612→                </tr>
   613→              </thead>
   614→              <tbody>
   615→                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
   616→                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Projected Variance</td>
   617→                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
   618→                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedVariance);
   619→                    const isBest = result.projectedVariance === Math.min(...allValues);
   620→                    return (
   621→                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
   622→                        {result.projectedVariance}%{isBest && ' ✓'}
   623→                      </td>
   624→                    );
   625→                  })}
   626→                </tr>
   627→                <tr style={{ borderBottom: '1px solid #e1e8ed' }}>
   628→                  <td style={{ padding: 12, fontSize: 14, fontWeight: 500, color: '#182026' }}>Dead Running</td>
   629→                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
   630→                    const allValues = Array.from(comparisonResults.values()).map((r) => r.projectedDeadRunning);
   631→                    const isBest = result.projectedDeadRunning === Math.min(...allValues);
   632→                    return (
   633→                      <td key={id} style={{ padding: 12, textAlign: 'center', fontSize: 14, backgroundColor: isBest ? '#ecfdf5' : 'transparent', fontWeight: isBest ? 700 : 400, color: isBest ? '#166534' : '#5c7080' }}>
   634→                        {result.projectedDeadRunning} km{isBest && ' ✓'}
   635→                      </td>
   636→                    );
   637→                  })}
   638→                </tr>
   639→              </tbody>
   640→            </table>
   641→          </div>
   642→
   643→          <div style={{ padding: 16, backgroundColor: '#f5f8fa', borderTop: '1px solid #e1e8ed', display: 'flex', justifyContent: 'flex-end' }}>
   644→            <Button
   645→              minimal
   646→              onClick={() => {
   647→                setComparisonResults(new Map());
   648→                setSelectedForComparison(new Set());
   649→              }}
   650→            >
   651→              Clear Comparison
   652→            </Button>
   653→          </div>
   654→        </Card>
   655→      )}
   656→
   657→      {/* Empty State */}
   658→      {scenarios.length === 0 && (
   659→        <Card elevation={Elevation.ONE} style={{ padding: 48, textAlign: 'center' }}>
   660→          <div style={{ fontSize: 48, marginBottom: 16 }}>🔬</div>
   661→          <h3 style={{ margin: '0 0 8px', fontSize: 18, fontWeight: 500, color: '#182026' }}>
   662→            No Scenarios Yet
   663→          </h3>
   664→          <p style={{ margin: 0, color: '#5c7080' }}>
   665→            Create a scenario above to start testing allocation strategies
   666→          </p>
   667→        </Card>
   668→      )}
   669→    </div>
   670→  );
   671→}
