                  {selectedScenario?.id === scenario.id && (
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleRunSimulation();
                      }}
                      disabled={running}
                      className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 disabled:opacity-50 text-sm transition-colors"
                    >
                      {running ? 'Running...' : 'Run Simulation'}
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Allocation Editor - Issue #6 Fix */}
      {selectedScenario && (
        <div className="bg-white shadow rounded-lg overflow-hidden">
          <div className="p-4 border-b border-gray-200 bg-blue-50">
            <h3 className="font-semibold text-blue-800">
              Allocation Editor: {selectedScenario.name}
            </h3>
            <p className="text-sm text-blue-600">
              Assign trains to pending services. Changes: {allocationChanges.length}
            </p>
          </div>

          {loadingServices ? (
            <div className="p-8 text-center text-gray-500">
              Loading services and trains...
            </div>
          ) : pendingServices.length === 0 ? (
            <div className="p-8 text-center text-gray-500">
              No pending services found for today.
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                      Service
                    </th>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                      Route
                    </th>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                      Distance
                    </th>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                      Assign Train
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
