                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Summary */}
          <div className="p-4 bg-gray-50 border-t">
            <div className="flex items-center justify-between">
              <div>
                <span className="text-sm text-gray-600 mr-4">
                  Projected Variance: <strong>{simulationResult.projectedVariance}%</strong>
                </span>
                <span className="text-sm text-gray-600">
                  Dead Running: <strong>{simulationResult.projectedDeadRunning} km</strong>
                </span>
              </div>
              <button
                onClick={() => setShowApplyConfirm(true)}
                disabled={allocationChanges.length === 0}
                className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50 text-sm transition-colors"
              >
                Apply to Live
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Apply to Live Confirmation Modal */}
      {showApplyConfirm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-md w-full mx-4">
            <div className="p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-2">
                Confirm Apply to Live
              </h3>
              <p className="text-gray-600 mb-4">
                This will create {allocationChanges.length} new allocation(s) in the live system.
                This action cannot be undone.
              </p>

              <div className="bg-yellow-50 border border-yellow-200 rounded p-3 mb-4">
                <p className="text-sm text-yellow-800">
                  <strong>Changes to apply:</strong>
                </p>
                <ul className="text-sm text-yellow-700 mt-1">
                  {allocationChanges.slice(0, 5).map((change) => (
                    <li key={change.serviceId}>
                      • {change.serviceCode}: Assign train {change.newTrainId.slice(0, 8)}...
                    </li>
                  ))}
                  {allocationChanges.length > 5 && (
                    <li>... and {allocationChanges.length - 5} more</li>
                  )}
                </ul>
              </div>

              <div className="flex gap-3 justify-end">
                <button
                  onClick={() => setShowApplyConfirm(false)}
                  className="px-4 py-2 text-gray-600 hover:text-gray-800"
                >
                  Cancel
                </button>
                <button
                  onClick={handleApplyToLive}
                  disabled={applying}
                  className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50"
                >
                  {applying ? 'Applying...' : 'Confirm Apply'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Multi-Scenario Comparison Results (Issue #7 Fix) */}
      {comparisonResults.size >= 2 && (
        <div className="bg-white shadow rounded-lg overflow-hidden">
          <div className="p-4 border-b border-gray-200 bg-purple-50">
            <h3 className="font-semibold text-purple-800">
              Scenario Comparison ({comparisonResults.size} scenarios)
            </h3>
            <p className="text-sm text-purple-600">
              Side-by-side comparison of selected scenarios
            </p>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                    Metric
                  </th>
                  {Array.from(comparisonResults.keys()).map((scenarioId) => {
                    const scenario = scenarios.find((s) => s.id === scenarioId);
                    return (
                      <th
                        key={scenarioId}
                        className="px-4 py-3 text-center text-xs font-medium text-gray-500 uppercase"
                      >
                        {scenario?.name || 'Scenario'}
                      </th>
                    );
                  })}
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {/* Variance comparison */}
                <tr>
                  <td className="px-4 py-3 text-sm font-medium text-gray-900">
                    Projected Variance
                  </td>
                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
                    const allValues = Array.from(comparisonResults.values()).map(
                      (r) => r.projectedVariance
                    );
                    const isBest = result.projectedVariance === Math.min(...allValues);
                    return (
                      <td
                        key={id}
                        className={`px-4 py-3 text-sm text-center ${
                          isBest
                            ? 'bg-green-100 text-green-800 font-bold'
                            : 'text-gray-600'
                        }`}
                      >
                        {result.projectedVariance}%
                        {isBest && ' ✓'}
                      </td>
                    );
                  })}
                </tr>
                {/* Dead Running comparison */}
                <tr>
                  <td className="px-4 py-3 text-sm font-medium text-gray-900">
                    Dead Running
                  </td>
                  {Array.from(comparisonResults.entries()).map(([id, result]) => {
                    const allValues = Array.from(comparisonResults.values()).map(
                      (r) => r.projectedDeadRunning
                    );
                    const isBest = result.projectedDeadRunning === Math.min(...allValues);
                    return (
                      <td
                        key={id}
                        className={`px-4 py-3 text-sm text-center ${
                          isBest
                            ? 'bg-green-100 text-green-800 font-bold'
                            : 'text-gray-600'
                        }`}
                      >
                        {result.projectedDeadRunning} km
                        {isBest && ' ✓'}
                      </td>
                    );
                  })}
                </tr>
              </tbody>
            </table>
          </div>

          {/* Actions */}
          <div className="p-4 bg-gray-50 border-t flex justify-end gap-4">
            <button
              onClick={() => {
                setComparisonResults(new Map());
                setSelectedForComparison(new Set());
              }}
              className="px-4 py-2 text-gray-600 hover:text-gray-800"
            >
              Clear Comparison
            </button>
          </div>
        </div>
      )}

      {/* Empty State */}
      {scenarios.length === 0 && (
        <div className="bg-gray-100 border border-gray-200 rounded-lg p-8 text-center">
          <div className="text-4xl mb-4">🔬</div>
          <h3 className="text-lg font-medium text-gray-900 mb-2">
            No Scenarios Yet
          </h3>
          <p className="text-gray-600">
            Create a scenario above to start testing allocation strategies
          </p>
        </div>
      )}
    </div>
  );
}

