  endDate: string;
}

type ViewMode = 'week' | '2-week' | '4-week';

const MAINTENANCE_COLORS: Record<string, { bg: string; color: string }> = {
  PM1: { bg: '#93c5fd', color: '#1e40af' },
  PM2: { bg: '#3b82f6', color: '#ffffff' },
  HM: { bg: '#f87171', color: '#ffffff' },
  OVH: { bg: '#c084fc', color: '#ffffff' },
};

const MAINTENANCE_INTENTS: Record<string, Intent> = {
  PM1: Intent.PRIMARY,
  PM2: Intent.PRIMARY,
  HM: Intent.DANGER,
  OVH: Intent.NONE,
};

// Create toaster for undo notifications
const toaster = typeof window !== 'undefined' ? Toaster.create({ position: Position.BOTTOM_RIGHT }) : null;

/**
 * Maintenance Gantt Component
 *
 * Interactive Gantt chart for maintenance scheduling.
 */
export function MaintenanceGantt() {
  const [ganttData, setGanttData] = useState<GanttData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<ViewMode>('4-week');
  const [selectedFleet, setSelectedFleet] = useState<string>('all');
  const [draggingEvent, setDraggingEvent] = useState<MaintenanceEvent | null>(null);
  const [validDropZones, setValidDropZones] = useState<Set<string>>(new Set());
  const [undoAction, setUndoAction] = useState<{ event: MaintenanceEvent; originalDate: string } | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Generate dates array based on view mode
  const generateDates = useCallback(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const dates: Date[] = [];
    const days = viewMode === 'week' ? 7 : viewMode === '2-week' ? 14 : 28;

    for (let i = 0; i < days; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() + i);
      dates.push(date);
    }
    return dates;
  }, [viewMode]);

  const dates = generateDates();

  const fetchGanttData = useCallback(async () => {
    setLoading(true);
    setError(null);

    const { data, error } = await apiFetch<GanttData>('/api/maintenance/gantt');

    if (error) {
      setError(error);
    } else if (data) {
      setGanttData(data);
    }

    setLoading(false);
  }, []);

  useEffect(() => {
    fetchGanttData();
  }, [fetchGanttData]);

  // Clear undo after 10 seconds
  useEffect(() => {
    if (undoAction) {
      const timer = setTimeout(() => setUndoAction(null), 10000);
      return () => clearTimeout(timer);
    }
  }, [undoAction]);

  const handleDragStart = (event: MaintenanceEvent, e: React.DragEvent) => {
    setDraggingEvent(event);
    e.dataTransfer.effectAllowed = 'move';
    const validZones = new Set<string>();
    dates.forEach((date) => {
      const dateStr = date.toISOString().split('T')[0];
      if (date >= new Date()) {
        validZones.add(`${event.trainId}-${dateStr}`);
      }
    });
    setValidDropZones(validZones);
  };

  const handleDragEnd = () => {
    setDraggingEvent(null);
    setValidDropZones(new Set());
  };

  const handleDragOver = (trainId: string, dateStr: string, e: React.DragEvent) => {
    e.preventDefault();
    const zoneKey = `${trainId}-${dateStr}`;
    if (validDropZones.has(zoneKey)) {
      e.dataTransfer.dropEffect = 'move';
    } else {
      e.dataTransfer.dropEffect = 'none';
    }
  };

  const handleDrop = async (trainId: string, newDateStr: string, e: React.DragEvent) => {
    e.preventDefault();
    if (!draggingEvent) return;

    const zoneKey = `${trainId}-${newDateStr}`;
    if (!validDropZones.has(zoneKey)) {
      return;
    }

    const originalDate = draggingEvent.startDate;

    // Optimistic update
    setGanttData((prev) => {
      if (!prev) return prev;
      return {
        ...prev,
        trains: prev.trains.map((train) => ({
          ...train,
          events: train.events.map((evt) =>
            evt.id === draggingEvent.id
              ? { ...evt, startDate: newDateStr, endDate: newDateStr }
              : evt
          ),
        })),
      };
    });

    // Save undo action
    setUndoAction({ event: draggingEvent, originalDate });

    // API call to persist
    await apiFetch(`/api/maintenance/schedule/${draggingEvent.id}`, {
      method: 'PUT',
      body: JSON.stringify({ startDate: newDateStr }),
    });

    setDraggingEvent(null);
    setValidDropZones(new Set());
  };

  const handleUndo = async () => {
    if (!undoAction) return;

    setGanttData((prev) => {
      if (!prev) return prev;
      return {
        ...prev,
        trains: prev.trains.map((train) => ({
          ...train,
          events: train.events.map((evt) =>
            evt.id === undoAction.event.id
              ? { ...evt, startDate: undoAction.originalDate, endDate: undoAction.originalDate }
              : evt
          ),
        })),
      };
    });

    await apiFetch(`/api/maintenance/schedule/${undoAction.event.id}`, {
      method: 'PUT',
      body: JSON.stringify({ startDate: undoAction.originalDate }),
    });

    setUndoAction(null);
  };

  // Filter trains by fleet
  const filteredTrains = ganttData?.trains.filter((train) =>
    selectedFleet === 'all' || train.fleetName === selectedFleet
  ) || [];

  // Get unique fleets for filter
  const fleets = Array.from(new Set(ganttData?.trains.map((t) => t.fleetName) || []));

  // Check if a date is today
  const isToday = (date: Date) => {
    const today = new Date();
    return date.toDateString() === today.toDateString();
  };

  if (loading) {
    return (
      <Card elevation={Elevation.ONE} style={{ padding: 48, textAlign: 'center' }}>
        <Spinner size={32} />
        <p style={{ marginTop: 16, color: '#5c7080' }}>Loading maintenance timeline...</p>
      </Card>
    );
  }

  if (error) {
    return (
      <Callout intent={Intent.DANGER} title="Error">
        {error}
      </Callout>
    );
  }

  return (
    <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
      {/* Header with Controls */}
      <div style={{ padding: 16, borderBottom: '1px solid #e1e8ed', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 16 }}>
        <h2 style={{ margin: 0, fontSize: 18, fontWeight: 600, color: '#182026' }}>Maintenance Timeline</h2>

        <div style={{ display: 'flex', alignItems: 'center', gap: 16, flexWrap: 'wrap' }}>
          {/* View Mode Toggle */}
          <ButtonGroup>
            {(['week', '2-week', '4-week'] as ViewMode[]).map((mode) => (
              <Button
                key={mode}
                active={viewMode === mode}
                onClick={() => setViewMode(mode)}
                intent={viewMode === mode ? Intent.PRIMARY : Intent.NONE}
                small
              >
                {mode === 'week' ? '1 Week' : mode === '2-week' ? '2 Weeks' : '4 Weeks'}
              </Button>
            ))}
          </ButtonGroup>

          {/* Fleet Filter */}
          <HTMLSelect
            value={selectedFleet}
            onChange={(e) => setSelectedFleet(e.target.value)}
          >
            <option value="all">All Fleets</option>
            {fleets.map((fleet) => (
              <option key={fleet} value={fleet}>
                {fleet}
              </option>
            ))}
          </HTMLSelect>
        </div>
      </div>

      {/* Undo Toast */}
      {undoAction && (
        <div style={{ position: 'fixed', bottom: 16, right: 16, backgroundColor: '#30404d', color: 'white', padding: '12px 16px', borderRadius: 4, boxShadow: '0 4px 8px rgba(0,0,0,0.2)', display: 'flex', alignItems: 'center', gap: 16, zIndex: 50 }}>
          <span>Moved {undoAction.event.type} for {undoAction.event.trainCode}</span>
          <Button small onClick={handleUndo}>Undo</Button>
        </div>
      )}

      {/* Legend */}
      <div style={{ padding: '8px 16px', backgroundColor: '#f5f8fa', borderBottom: '1px solid #e1e8ed', display: 'flex', alignItems: 'center', gap: 16, flexWrap: 'wrap' }}>
        <span style={{ fontSize: 14, fontWeight: 500, color: '#5c7080' }}>Legend:</span>
        {Object.entries(MAINTENANCE_COLORS).map(([type, colors]) => (
          <Tag key={type} style={{ backgroundColor: colors.bg, color: colors.color }}>
            {type}
          </Tag>
        ))}
      </div>

      {/* Gantt Chart */}
      <div ref={containerRef} style={{ overflowX: 'auto' }}>
        <div style={{ minWidth: `${dates.length * 60 + 200}px` }}>
          {/* Header Row - Dates */}
          <div style={{ display: 'flex', borderBottom: '1px solid #e1e8ed', backgroundColor: '#f5f8fa', position: 'sticky', top: 0, zIndex: 10 }}>
            <div style={{ width: 192, flexShrink: 0, padding: '8px 16px', fontWeight: 500, color: '#5c7080', borderRight: '1px solid #e1e8ed' }}>
              Train
            </div>
            {dates.map((date) => {
              const dateStr = date.toISOString().split('T')[0];
              const dayName = date.toLocaleDateString('en-US', { weekday: 'short' });
              const dayNum = date.getDate();
              const isWeekend = date.getDay() === 0 || date.getDay() === 6;

              return (
                <div
                  key={dateStr}
                  style={{
                    width: 56,
                    flexShrink: 0,
                    textAlign: 'center',
                    padding: '8px 0',
                    fontSize: 12,
                    borderRight: '1px solid #f0f0f0',
                    backgroundColor: isToday(date) ? '#e1e8ed' : isWeekend ? '#f5f8fa' : 'transparent',
                    fontWeight: isToday(date) ? 700 : 400,
                    color: isToday(date) ? '#2563eb' : '#5c7080',
                  }}
                >
                  <div style={{ fontWeight: 500 }}>{dayName}</div>
                  <div>{dayNum}</div>
                </div>
              );
            })}
          </div>

          {/* Train Rows */}
          {filteredTrains.length === 0 ? (
            <div style={{ padding: 32, textAlign: 'center', color: '#5c7080' }}>
              No trains match the selected filter
            </div>
          ) : (
            filteredTrains.map((train) => (
              <div key={train.id} style={{ display: 'flex', borderBottom: '1px solid #f0f0f0' }}>
                {/* Train Info */}
                <div style={{ width: 192, flexShrink: 0, padding: '12px 16px', borderRight: '1px solid #e1e8ed' }}>
                  <div className="train-id" style={{ fontWeight: 600, color: '#182026' }}>{train.trainId}</div>
                  <div style={{ fontSize: 12, color: '#5c7080' }}>
                    {train.fleetName} • {train.depotCode}
                  </div>
                </div>

                {/* Date Cells */}
                {dates.map((date) => {
                  const dateStr = date.toISOString().split('T')[0];
                  const event = train.events.find((e) => e.startDate === dateStr);
                  const isWeekend = date.getDay() === 0 || date.getDay() === 6;
                  const zoneKey = `${train.trainId}-${dateStr}`;
                  const isValidDrop = validDropZones.has(zoneKey);
                  const isInvalidDrop = draggingEvent && !isValidDrop && draggingEvent.trainId === train.trainId;

                  return (
                    <div
                      key={`${train.id}-${dateStr}`}
                      style={{
                        width: 56,
                        height: 48,
                        flexShrink: 0,
                        borderRight: '1px solid #f0f0f0',
                        position: 'relative',
                        backgroundColor: draggingEvent && isValidDrop ? '#d1fae5' : isToday(date) ? '#eff6ff' : isWeekend ? '#f9fafb' : 'transparent',
                        outline: draggingEvent && isValidDrop ? '2px solid #10b981' : isInvalidDrop ? '2px solid #ef4444' : 'none',
                        outlineOffset: -2,
                      }}
                      onDragOver={(e) => handleDragOver(train.trainId, dateStr, e)}
                      onDrop={(e) => handleDrop(train.trainId, dateStr, e)}
                    >
                      {/* Today Line */}
                      {isToday(date) && (
                        <div style={{ position: 'absolute', left: '50%', top: 0, bottom: 0, width: 2, backgroundColor: '#2563eb', zIndex: 10 }} />
                      )}

                      {/* Maintenance Block */}
                      {event && (
                        <div
                          draggable
                          onDragStart={(e) => handleDragStart(event, e)}
                          onDragEnd={handleDragEnd}
                          style={{
                            position: 'absolute',
                            top: 4,
                            left: 4,
                            right: 4,
                            bottom: 4,
                            borderRadius: 4,
                            cursor: 'move',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontSize: 11,
                            fontWeight: 600,
                            backgroundColor: MAINTENANCE_COLORS[event.type]?.bg || '#d1d5db',
                            color: MAINTENANCE_COLORS[event.type]?.color || '#374151',
                            boxShadow: '0 1px 2px rgba(0,0,0,0.1)',
                          }}
                          title={`${event.type}\nDepot: ${event.depotName}\nKm: ${event.kmAtMaintenance.toLocaleString()}`}
                        >
                          {event.type}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            ))
          )}
        </div>
      </div>

      {/* Empty State */}
      {!ganttData?.trains.length && (
        <div style={{ padding: 32, textAlign: 'center', color: '#5c7080' }}>
          No maintenance schedules to display
        </div>
      )}
    </Card>
  );
}

