/**
 * Allocation Page
 *
 * Main interface for train-to-service allocation.
 * Enables dispatchers to view pending services and assign trains
 * using AI-powered recommendations with visible justifications.
 */

import { AllocationPanel } from '@/components/allocation';

export default function AllocationPage() {
  return (
    <div className="space-y-6">
      <div className="bg-white shadow rounded-lg p-6">
        <h1 className="text-2xl font-bold text-gray-900">Train Allocation</h1>
        <p className="mt-2 text-gray-600">
          Assign trains to services using AI-powered recommendations optimized for mileage balancing
        </p>
      </div>

      <AllocationPanel />
    </div>
  );
}

import { DashboardKPIs, DepotCapacityCards, MaintenanceAlerts } from '@/components/dashboard';

export default function Home() {
  return (
    <div className="space-y-6">
      <div className="bg-panel rounded-lg p-6 border border-border">
        <h1 className="text-2xl font-bold text-text-primary">
          MMS Dashboard
        </h1>
        <p className="mt-2 text-text-secondary">
          Railway Fleet Mileage Management System - Demo Version
        </p>
      </div>

      {/* Fleet Summary KPIs - Story 2.1 */}
      <section>
        <h2 className="text-lg font-semibold text-text-secondary mb-4">Fleet Overview</h2>
        <DashboardKPIs />
      </section>

      {/* Depot Capacity Cards - Story 2.3 */}
      <section>
        <h2 className="text-lg font-semibold text-text-secondary mb-4">Depot Capacity</h2>
        <DepotCapacityCards />
      </section>

      {/* Maintenance Alerts - Story 2.4 */}
      <section>
        <h2 className="text-lg font-semibold text-text-secondary mb-4">Maintenance Alerts</h2>
        <MaintenanceAlerts />
      </section>
    </div>
  );
}

/**
 * Fleet List Page
 *
 * Displays list of trains with filtering capabilities.
 * Can be filtered by status (fit/unfit) or depot.
 */

import { Suspense } from 'react';

interface FleetPageProps {
  searchParams: Promise<{ status?: string; depot?: string }>;
}

export default async function FleetPage({ searchParams }: FleetPageProps) {
  const params = await searchParams;
  const { status, depot } = params;

  return (
    <div className="space-y-6">
      <div className="bg-white shadow rounded-lg p-6">
        <h1 className="text-2xl font-bold text-gray-900">Fleet Overview</h1>
        <p className="mt-2 text-gray-600">
          Train list with status and mileage information
        </p>
      </div>

      {/* Filter Indicators */}
      <div className="flex flex-wrap gap-2">
        {status && (
          <span className="px-3 py-1 bg-blue-100 text-blue-800 rounded-full text-sm">
            Filter: Status = {status}
          </span>
        )}
        {depot && (
          <span className="px-3 py-1 bg-purple-100 text-purple-800 rounded-full text-sm">
            Filter: Depot = {depot}
          </span>
        )}
      </div>

      {/* Placeholder for train list - Epic 3 */}
      <div className="bg-gray-100 border border-gray-200 rounded-lg p-8 text-center text-gray-500">
        <p className="mb-2">Train list will be implemented in Epic 3</p>
        <p className="text-sm">Showing trains with filters: {JSON.stringify({ status, depot })}</p>
      </div>
    </div>
  );
}

