   185→            </button>
   186→          )}
   187→        </div>
   188→      )}
   189→    </div>
   190→  );
   191→}
   192→
   193→// Generate demo events for visualization
   194→function generateDemoEvents(): MaintenanceEvent[] {
   195→  const events: MaintenanceEvent[] = [];
   196→  const types: ('PM1' | 'PM2' | 'HM' | 'OVH')[] = ['PM1', 'PM2', 'HM', 'OVH'];
   197→  const depots = ['LIS', 'PRT', 'FAR', 'BRG'];
   198→  const trainPrefixes = ['EMU', 'DMU', 'LOC'];
   199→
   200→  const now = Date.now();
   201→  const msPerDay = 24 * 60 * 60 * 1000;
   202→
   203→  // Generate 50 demo events spread over 2 years
   204→  for (let i = 0; i < 50; i++) {
