'use client';

import React, { useState, useCallback, useEffect } from 'react';
import { apiFetch } from '@/lib/api';

interface DepotWeek {
  depotId: string;
  depotName: string;
  depotCode: string;
  week: string;
  weekStart: string;
  weekEnd: string;
  scheduled: number;
  capacity: number;
  utilization: number;
  trains: string[];
}

interface CapacityData {
  depots: {
    id: string;
    name: string;
    code: string;
    maxCapacity: number;
  }[];
  weeks: {
    week: string;
    start: string;
    end: string;
  }[];
  data: DepotWeek[];
}

/**
 * Depot Capacity Heatmap Component
 *
 * Shows weekly depot maintenance capacity utilization.
 * Color-coded: green (<70%), yellow (70-90%), red (>90%)
 */
export function DepotCapacityHeatmap() {
  const [capacityData, setCapacityData] = useState<CapacityData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedCell, setSelectedCell] = useState<DepotWeek | null>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);

    const { data, error } = await apiFetch<CapacityData>('/api/maintenance/depot-capacity');

    if (error) {
      setError(error);
    } else if (data) {
      setCapacityData(data);
    }

    setLoading(false);
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const getUtilizationColor = (utilization: number) => {
    if (utilization >= 100) return 'bg-red-500 text-white';
    if (utilization >= 90) return 'bg-red-400 text-white';
    if (utilization >= 70) return 'bg-yellow-400 text-gray-900';
    if (utilization >= 50) return 'bg-green-200 text-gray-900';
    if (utilization > 0) return 'bg-green-100 text-gray-900';
    return 'bg-gray-50 text-gray-400';
  };

  const getCellData = (depotId: string, week: string): DepotWeek | undefined => {
    return capacityData?.data.find((d) => d.depotId === depotId && d.week === week);
  };

  if (loading) {
    return (
      <div className="bg-white shadow rounded-lg p-6 animate-pulse">
        <div className="h-6 bg-gray-200 rounded w-1/4 mb-4"></div>
        <div className="h-64 bg-gray-200 rounded"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-lg p-6">
        <p className="text-red-800">
          <strong>Error:</strong> {error}
        </p>
      </div>
    );
  }

  if (!capacityData || capacityData.depots.length === 0) {
    return (
      <div className="bg-white shadow rounded-lg p-6 text-center text-gray-500">
        No depot capacity data available
      </div>
    );
  }

  return (
    <div className="bg-white shadow rounded-lg overflow-hidden">
      <div className="p-4 border-b border-gray-200">
        <h2 className="text-lg font-semibold text-gray-900">Depot Capacity per Week</h2>
        <p className="text-sm text-gray-600 mt-1">
          Click a cell to see scheduled trains
        </p>
      </div>

      {/* Legend */}
      <div className="px-4 py-2 bg-gray-50 border-b border-gray-200 flex items-center gap-4 flex-wrap">
        <span className="text-sm text-gray-600 font-medium">Utilization:</span>
        <span className="px-2 py-1 text-xs bg-green-100 text-gray-900 rounded">&lt;50%</span>
        <span className="px-2 py-1 text-xs bg-green-200 text-gray-900 rounded">50-70%</span>
        <span className="px-2 py-1 text-xs bg-yellow-400 text-gray-900 rounded">70-90%</span>
        <span className="px-2 py-1 text-xs bg-red-400 text-white rounded">&gt;90%</span>
        <span className="px-2 py-1 text-xs bg-red-500 text-white rounded">100%</span>
      </div>

      {/* Heatmap Grid */}
      <div className="overflow-x-auto p-4">
        <table className="w-full">
          <thead>
            <tr>
              <th className="px-4 py-2 text-left text-sm font-medium text-gray-700 border-b border-gray-200">
                Depot
              </th>
              {capacityData.weeks.map((week) => (
                <th
                  key={week.week}
                  className="px-4 py-2 text-center text-sm font-medium text-gray-700 border-b border-gray-200"
                >
                  <div>{week.week}</div>
                  <div className="text-xs font-normal text-gray-500">
                    {new Date(week.start).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {capacityData.depots.map((depot) => (
              <tr key={depot.id} className="hover:bg-gray-50">
                <td className="px-4 py-3 border-b border-gray-100">
                  <div className="font-medium text-gray-900">{depot.name}</div>
                  <div className="text-xs text-gray-500">
                    {depot.code} • Capacity: {depot.maxCapacity}/week
                  </div>
                </td>
                {capacityData.weeks.map((week) => {
                  const cellData = getCellData(depot.id, week.week);
                  const utilization = cellData?.utilization || 0;
                  const isAtCapacity = utilization >= 100;

                  return (
                    <td
                      key={`${depot.id}-${week.week}`}
                      className="px-2 py-2 border-b border-gray-100 text-center"
                    >
                      <button
                        onClick={() => cellData && setSelectedCell(cellData)}
                        className={`w-full py-3 px-2 rounded transition-all ${getUtilizationColor(
                          utilization
                        )} ${
                          cellData && cellData.scheduled > 0
                            ? 'cursor-pointer hover:ring-2 hover:ring-primary-500'
                            : 'cursor-default'
                        }`}
                        disabled={!cellData || cellData.scheduled === 0}
                      >
                        <div className="text-sm font-semibold">
                          {cellData?.scheduled || 0}/{depot.maxCapacity}
                        </div>
                        <div className="text-xs opacity-80">
                          {utilization.toFixed(0)}%
                          {isAtCapacity && ' ⚠️'}
                        </div>
                      </button>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Selected Cell Details Modal */}
      {selectedCell && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl max-w-md w-full mx-4">
            <div className="p-4 border-b border-gray-200 flex items-center justify-between">
              <div>
                <h3 className="font-semibold text-gray-900">
                  {selectedCell.depotName} - {selectedCell.week}
                </h3>
                <p className="text-sm text-gray-500">
                  {new Date(selectedCell.weekStart).toLocaleDateString()} -{' '}
                  {new Date(selectedCell.weekEnd).toLocaleDateString()}
                </p>
              </div>
              <button
                onClick={() => setSelectedCell(null)}
                className="text-gray-400 hover:text-gray-600"
              >
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
            <div className="p-4">
              <div className="mb-4">
                <div className="text-sm text-gray-600">Scheduled Maintenance</div>
                <div className="text-2xl font-bold text-gray-900">
                  {selectedCell.scheduled} / {selectedCell.capacity}
                </div>
                <div className={`text-sm ${selectedCell.utilization >= 90 ? 'text-red-600' : 'text-gray-500'}`}>
                  {selectedCell.utilization.toFixed(0)}% capacity used
                </div>
              </div>

              {selectedCell.trains.length > 0 && (
                <div>
                  <div className="text-sm font-medium text-gray-700 mb-2">
                    Trains Scheduled:
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {selectedCell.trains.map((train) => (
                      <span
                        key={train}
                        className="px-2 py-1 bg-gray-100 text-gray-800 text-sm font-mono rounded"
                      >
                        {train}
                      </span>
                    ))}
                  </div>
                </div>
              )}

              {selectedCell.trains.length === 0 && (
                <p className="text-gray-500 text-sm">No trains scheduled</p>
              )}
            </div>
            <div className="p-4 border-t border-gray-200 bg-gray-50">
              <button
                onClick={() => setSelectedCell(null)}
                className="w-full px-4 py-2 bg-primary-600 text-white rounded hover:bg-primary-700 transition-colors"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

