   187→
   188→      // Add timeline ruler
   189→      renderTimelineRuler(contentContainer, startDate, endDate, lod);
   190→    },
   191→    [onEventSelect, onEventHover]
   192→  );
   193→
   194→  return (
   195→    <div style={{ position: 'relative' }}>
   196→      {/* Canvas container */}
   197→      <div ref={containerRef} style={{ borderRadius: 4, overflow: 'hidden' }} />
   198→
   199→      {/* Overlay controls */}
   200→      <Card
   201→        elevation={Elevation.TWO}
   202→        style={{
   203→          position: 'absolute',
   204→          top: 16,
   205→          left: 16,
   206→          padding: 12,
   207→          backgroundColor: 'rgba(255, 255, 255, 0.95)',
   208→        }}
   209→      >
   210→        <div style={{ fontSize: 12, color: '#5c7080', marginBottom: 4 }}>LOD Level</div>
   211→        <div style={{ fontSize: 14, fontWeight: 500, color: '#182026' }}>
   212→          {LOD_LABELS[currentLOD as keyof typeof LOD_LABELS]}
   213→        </div>
   214→        <div style={{ fontSize: 12, color: '#8a9ba8', marginTop: 4 }}>
   215→          Scale: {(scale * 100).toFixed(0)}%
   216→        </div>
   217→      </Card>
   218→
   219→      {/* Zoom controls */}
   220→      <div style={{ position: 'absolute', bottom: 16, right: 16, display: 'flex', gap: 8 }}>
   221→        <Button
   222→          onClick={() => viewportRef.current?.zoomPercent(0.2, true)}
   223→          style={{ minWidth: 36 }}
   224→        >
   225→          +
   226→        </Button>
   227→        <Button
   228→          onClick={() => viewportRef.current?.zoomPercent(-0.2, true)}
   229→          style={{ minWidth: 36 }}
   230→        >
   231→          -
   232→        </Button>
   233→        <Button
   234→          small
   235→          onClick={() => {
   236→            viewportRef.current?.fit();
   237→            viewportRef.current?.moveCenter(width / 2, height / 2);
   238→          }}
   239→        >
   240→          Fit
   241→        </Button>
   242→      </div>
   243→    </div>
   244→  );
   245→}
   246→
   247→// LOD 0: Strategic View (10-12 years) - Heatmap aggregation
   248→function renderStrategicView(
   249→  container: Container,
   250→  events: MaintenanceEvent[],
   251→  startDate: Date,
   252→  endDate: Date
   253→) {
   254→  const graphics = new Graphics();
   255→  container.addChild(graphics);
   256→
   257→  // Calculate yearly aggregations
   258→  const yearlyData = new Map<number, { PM1: number; PM2: number; HM: number; OVH: number }>();
   259→
   260→  events.forEach((event) => {
   261→    const year = event.startDate.getFullYear();
   262→    if (!yearlyData.has(year)) {
   263→      yearlyData.set(year, { PM1: 0, PM2: 0, HM: 0, OVH: 0 });
   264→    }
   265→    const data = yearlyData.get(year)!;
   266→    data[event.type]++;
   267→  });
   268→
   269→  // Render yearly blocks
   270→  const years = Array.from(yearlyData.keys()).sort();
   271→  const blockWidth = 100;
   272→  const blockHeight = 80;
   273→
   274→  years.forEach((year, index) => {
   275→    const data = yearlyData.get(year)!;
   276→    const total = data.PM1 + data.PM2 + data.HM + data.OVH;
   277→    const intensity = Math.min(1, total / 50); // Normalize
   278→
   279→    graphics.rect(
   280→      index * (blockWidth + 10) + 20,
   281→      HEADER_HEIGHT,
   282→      blockWidth,
   283→      blockHeight
   284→    );
   285→    graphics.fill({ color: 0x3B82F6, alpha: 0.3 + intensity * 0.7 });
   286→
   287→    // Year label
   288→    const style = new TextStyle({
   289→      fontSize: 14,
   290→      fill: 0xFAFAFA,
   291→      fontFamily: 'Inter',
   292→    });
   293→    const yearText = new Text({ text: year.toString(), style });
   294→    yearText.x = index * (blockWidth + 10) + 20 + blockWidth / 2 - yearText.width / 2;
   295→    yearText.y = HEADER_HEIGHT + blockHeight + 5;
   296→    container.addChild(yearText);
   297→
   298→    // Count label
   299→    const countStyle = new TextStyle({
   300→      fontSize: 20,
   301→      fill: 0xFAFAFA,
   302→      fontWeight: 'bold',
   303→      fontFamily: 'Inter',
   304→    });
   305→    const countText = new Text({ text: total.toString(), style: countStyle });
   306→    countText.x = index * (blockWidth + 10) + 20 + blockWidth / 2 - countText.width / 2;
   307→    countText.y = HEADER_HEIGHT + blockHeight / 2 - countText.height / 2;
   308→    container.addChild(countText);
   309→  });
   310→}
   311→
   312→// LOD 1: Tactical View (1-3 years) - Campaign bars
   313→function renderTacticalView(
   314→  container: Container,
   315→  events: MaintenanceEvent[],
   316→  startDate: Date,
   317→  endDate: Date
   318→) {
   319→  const graphics = new Graphics();
   320→  container.addChild(graphics);
   321→
   322→  // Calculate quarterly aggregations
   323→  const quarterlyData = new Map<string, { PM1: number; PM2: number; HM: number; OVH: number }>();
   324→
   325→  events.forEach((event) => {
   326→    const year = event.startDate.getFullYear();
   327→    const quarter = Math.floor(event.startDate.getMonth() / 3) + 1;
   328→    const key = `${year}-Q${quarter}`;
   329→
   330→    if (!quarterlyData.has(key)) {
   331→      quarterlyData.set(key, { PM1: 0, PM2: 0, HM: 0, OVH: 0 });
   332→    }
   333→    const data = quarterlyData.get(key)!;
   334→    data[event.type]++;
   335→  });
   336→
   337→  // Render quarterly bars
   338→  const quarters = Array.from(quarterlyData.keys()).sort();
   339→  const barWidth = 60;
   340→  const maxHeight = 150;
   341→
   342→  quarters.forEach((quarter, index) => {
   343→    const data = quarterlyData.get(quarter)!;
   344→    let yOffset = HEADER_HEIGHT;
   345→
   346→    // Stack by type
   347→    (['PM1', 'PM2', 'HM', 'OVH'] as const).forEach((type) => {
   348→      const count = data[type];
   349→      if (count > 0) {
   350→        const height = (count / 20) * maxHeight;
   351→        graphics.rect(
   352→          index * (barWidth + 5) + 20,
   353→          yOffset,
   354→          barWidth,
   355→          height
   356→        );
   357→        graphics.fill({ color: MAINTENANCE_COLORS[type] });
   358→        yOffset += height;
   359→      }
   360→    });
   361→
   362→    // Quarter label
   363→    const style = new TextStyle({
   364→      fontSize: 10,
   365→      fill: 0xA1A1A1,
   366→      fontFamily: 'Inter',
   367→    });
   368→    const text = new Text({ text: quarter, style });
   369→    text.x = index * (barWidth + 5) + 20 + barWidth / 2 - text.width / 2;
   370→    text.y = HEADER_HEIGHT + maxHeight + 5;
   371→    container.addChild(text);
   372→  });
   373→}
   374→
   375→// LOD 2: Operational View (1-6 months) - Work orders as blocks
   376→function renderOperationalView(
   377→  container: Container,
   378→  events: MaintenanceEvent[],
   379→  startDate: Date,
   380→  endDate: Date
   381→) {
   382→  const graphics = new Graphics();
   383→  container.addChild(graphics);
   384→
   385→  // Group by train
   386→  const trainGroups = new Map<string, MaintenanceEvent[]>();
   387→  events.forEach((event) => {
   388→    if (!trainGroups.has(event.trainId)) {
   389→      trainGroups.set(event.trainId, []);
   390→    }
   391→    trainGroups.get(event.trainId)!.push(event);
   392→  });
   393→
   394→  const trains = Array.from(trainGroups.keys()).slice(0, 15); // Limit visible trains
   395→  const startTime = startDate.getTime();
   396→  const msPerDay = 24 * 60 * 60 * 1000;
   397→
   398→  trains.forEach((trainId, rowIndex) => {
   399→    const trainEvents = trainGroups.get(trainId)!;
   400→    const y = HEADER_HEIGHT + rowIndex * ROW_HEIGHT;
   401→
   402→    // Row background
   403→    graphics.rect(0, y, 2000, ROW_HEIGHT - 2);
   404→    graphics.fill({ color: rowIndex % 2 === 0 ? 0x141414 : 0x1C1C1C });
   405→
   406→    // Train label
   407→    const style = new TextStyle({
   408→      fontSize: 11,
   409→      fill: 0xA1A1A1,
   410→      fontFamily: 'JetBrains Mono',
   411→    });
   412→    const label = new Text({ text: trainEvents[0]?.trainName || trainId, style });
   413→    label.x = 10;
   414→    label.y = y + ROW_HEIGHT / 2 - label.height / 2;
   415→    container.addChild(label);
   416→
   417→    // Events
   418→    trainEvents.forEach((event) => {
   419→      const startOffset = (event.startDate.getTime() - startTime) / msPerDay;
   420→      const duration = (event.endDate.getTime() - event.startDate.getTime()) / msPerDay;
   421→
   422→      const x = 120 + startOffset * DAY_WIDTH;
   423→      const width = Math.max(duration * DAY_WIDTH, 8);
   424→
   425→      graphics.rect(x, y + 4, width, ROW_HEIGHT - 8);
   426→      graphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   427→    });
   428→  });
   429→}
   430→
   431→// LOD 3: Execution View (1-4 weeks) - Full task details
   432→function renderExecutionView(
   433→  container: Container,
   434→  events: MaintenanceEvent[],
   435→  startDate: Date,
   436→  endDate: Date,
   437→  onEventSelect?: (event: MaintenanceEvent) => void,
   438→  onEventHover?: (event: MaintenanceEvent | null) => void
   439→) {
   440→  const graphics = new Graphics();
   441→  container.addChild(graphics);
   442→
   443→  // Group by train
   444→  const trainGroups = new Map<string, MaintenanceEvent[]>();
   445→  events.forEach((event) => {
   446→    if (!trainGroups.has(event.trainId)) {
   447→      trainGroups.set(event.trainId, []);
   448→    }
   449→    trainGroups.get(event.trainId)!.push(event);
   450→  });
   451→
   452→  const trains = Array.from(trainGroups.keys()).slice(0, 20);
   453→  const startTime = startDate.getTime();
   454→  const msPerDay = 24 * 60 * 60 * 1000;
   455→
   456→  trains.forEach((trainId, rowIndex) => {
   457→    const trainEvents = trainGroups.get(trainId)!;
   458→    const y = HEADER_HEIGHT + rowIndex * ROW_HEIGHT;
   459→
   460→    // Row background
   461→    graphics.rect(0, y, 3000, ROW_HEIGHT - 2);
   462→    graphics.fill({ color: rowIndex % 2 === 0 ? 0x141414 : 0x1C1C1C });
   463→
   464→    // Train label
   465→    const style = new TextStyle({
   466→      fontSize: 12,
   467→      fill: 0xFAFAFA,
   468→      fontFamily: 'JetBrains Mono',
   469→    });
   470→    const label = new Text({ text: trainEvents[0]?.trainName || trainId, style });
   471→    label.x = 10;
   472→    label.y = y + ROW_HEIGHT / 2 - label.height / 2;
   473→    container.addChild(label);
   474→
   475→    // Events with full details
   476→    trainEvents.forEach((event) => {
   477→      const startOffset = (event.startDate.getTime() - startTime) / msPerDay;
   478→      const duration = (event.endDate.getTime() - event.startDate.getTime()) / msPerDay;
   479→
   480→      const x = 150 + startOffset * DAY_WIDTH * 2; // Larger scale at execution level
   481→      const width = Math.max(duration * DAY_WIDTH * 2, 30);
   482→
   483→      // Event block
   484→      const eventGraphics = new Graphics();
   485→      eventGraphics.rect(0, 0, width, ROW_HEIGHT - 10);
   486→      eventGraphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   487→
   488→      // Rounded corners simulation
   489→      eventGraphics.rect(0, 0, width, ROW_HEIGHT - 10);
   490→      eventGraphics.fill({ color: MAINTENANCE_COLORS[event.type] });
   491→
   492→      eventGraphics.x = x;
   493→      eventGraphics.y = y + 5;
   494→      eventGraphics.eventMode = 'static';
   495→      eventGraphics.cursor = 'pointer';
   496→
   497→      eventGraphics.on('pointerover', () => {
   498→        eventGraphics.alpha = 0.8;
   499→        onEventHover?.(event);
   500→      });
   501→
   502→      eventGraphics.on('pointerout', () => {
   503→        eventGraphics.alpha = 1;
   504→        onEventHover?.(null);
   505→      });
   506→
   507→      eventGraphics.on('pointertap', () => {
   508→        onEventSelect?.(event);
   509→      });
   510→
   511→      container.addChild(eventGraphics);
   512→
   513→      // Event type label
   514→      if (width > 40) {
   515→        const typeStyle = new TextStyle({
   516→          fontSize: 10,
   517→          fill: 0xFFFFFF,
   518→          fontWeight: 'bold',
   519→          fontFamily: 'Inter',
   520→        });
   521→        const typeText = new Text({ text: event.type, style: typeStyle });
   522→        typeText.x = x + 5;
   523→        typeText.y = y + 8;
   524→        container.addChild(typeText);
   525→
   526→        // Depot label
   527→        if (width > 80) {
   528→          const depotStyle = new TextStyle({
   529→            fontSize: 9,
   530→            fill: 0xCCCCCC, // Lighter color instead of alpha
   531→            fontFamily: 'Inter',
   532→          });
   533→          const depotText = new Text({ text: event.depot, style: depotStyle });
   534→          depotText.x = x + 5;
   535→          depotText.y = y + 22;
   536→          container.addChild(depotText);
   537→        }
   538→      }
   539→    });
   540→  });
   541→}
   542→
   543→// Timeline ruler
   544→function renderTimelineRuler(
   545→  container: Container,
   546→  startDate: Date,
   547→  endDate: Date,
   548→  lod: LODLevel
   549→) {
   550→  const graphics = new Graphics();
   551→  container.addChild(graphics);
   552→
   553→  // Header background
   554→  graphics.rect(0, 0, 3000, HEADER_HEIGHT);
   555→  graphics.fill({ color: 0x1C1C1C });
   556→
   557→  const style = new TextStyle({
   558→    fontSize: 11,
   559→    fill: 0xA1A1A1,
   560→    fontFamily: 'Inter',
   561→  });
   562→
   563→  // Different granularity based on LOD
   564→  const msPerDay = 24 * 60 * 60 * 1000;
   565→  const startTime = startDate.getTime();
   566→
   567→  if (lod >= 2) {
   568→    // Show months
   569→    const months = [];
   570→    let current = new Date(startDate);
   571→    while (current < endDate) {
   572→      months.push(new Date(current));
   573→      current.setMonth(current.getMonth() + 1);
   574→    }
   575→
   576→    months.forEach((month, index) => {
   577→      const offset = (month.getTime() - startTime) / msPerDay;
   578→      const x = 150 + offset * DAY_WIDTH * (lod === 3 ? 2 : 1);
   579→
   580→      // Month line
   581→      graphics.moveTo(x, HEADER_HEIGHT - 20);
   582→      graphics.lineTo(x, HEADER_HEIGHT);
   583→      graphics.stroke({ color: 0x2A2A2A, width: 1 });
   584→
   585→      // Month label
   586→      const monthLabel = month.toLocaleDateString('en-US', {
   587→        month: 'short',
   588→        year: '2-digit',
   589→      });
   590→      const text = new Text({ text: monthLabel, style });
   591→      text.x = x + 5;
   592→      text.y = HEADER_HEIGHT - 18;
   593→      container.addChild(text);
   594→    });
   595→  }
   596→}
   597→
   598→export default ScheduleCanvas;
   599→

toolUseResult.content:
'use client';

import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Application, Container, Graphics, Text, TextStyle } from 'pixi.js';
import { Viewport } from 'pixi-viewport';
import { Card, Elevation, Button } from '@blueprintjs/core';
import {
  LODLevel,
  getLODFromScale,
} from '@/stores/viewportStore';

interface MaintenanceEvent {
  id: string;
  trainId: string;
  trainName: string;
  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
  startDate: Date;
  endDate: Date;
  depot: string;
}

interface ScheduleCanvasProps {
  events: MaintenanceEvent[];
  onEventSelect?: (event: MaintenanceEvent) => void;
  onEventHover?: (event: MaintenanceEvent | null) => void;
  startDate?: Date;
  endDate?: Date;
  width?: number;
  height?: number;
}

// Color palette for maintenance types
const MAINTENANCE_COLORS = {
  PM1: 0x10B981, // Green
  PM2: 0x3B82F6, // Blue
  HM: 0xF59E0B,  // Amber
  OVH: 0xEF4444, // Red
};

// LOD level descriptions
const LOD_LABELS = {
  0: 'Strategic (10-12 years)',
  1: 'Tactical (1-3 years)',
  2: 'Operational (1-6 months)',
  3: 'Execution (1-4 weeks)',
};

// Day width in pixels at scale 1.0
const DAY_WIDTH = 20;
const ROW_HEIGHT = 40;
const HEADER_HEIGHT = 60;

export function ScheduleCanvas({
  events,
  onEventSelect,
  onEventHover,
  startDate = new Date(),
  endDate = new Date(Date.now() + 365 * 24 * 60 * 60 * 1000),
  width = 1200,
  height = 600,
}: ScheduleCanvasProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const appRef = useRef<Application | null>(null);
  const viewportRef = useRef<Viewport | null>(null);

  // Use local state for LOD and scale to avoid toolkit infinite loop issue
  const [currentLOD, setCurrentLOD] = useState<LODLevel>(2);
  const [scale, setScale] = useState(0.5);

  // Initialize Pixi application
  useEffect(() => {
    if (!containerRef.current) return;

    const app = new Application();

    const initApp = async () => {
      await app.init({
        width,
        height,
        backgroundColor: 0x0A0A0A, // Dark canvas background
        resolution: window.devicePixelRatio || 1,
        autoDensity: true,
        antialias: true,
      });

      containerRef.current?.appendChild(app.canvas);
      appRef.current = app;

      // Create viewport
      const viewport = new Viewport({
        screenWidth: width,
        screenHeight: height,
        worldWidth: width * 10,
        worldHeight: height * 5,
        events: app.renderer.events,
      });

      app.stage.addChild(viewport);
      viewportRef.current = viewport;

      // Enable viewport interactions
      viewport
        .drag()
        .pinch()
        .wheel()
        .decelerate()
        .clampZoom({
          minScale: 0.05,
          maxScale: 4.0,
        });

      // Listen to zoom/scale changes - update local state
      viewport.on('zoomed', () => {
        const newScale = viewport.scale.x;
        setScale(newScale);
        setCurrentLOD(getLODFromScale(newScale));
      });

      viewport.on('moved', () => {
        // Position tracking handled by viewport internally
      });

      // Initial render
      renderContent(viewport, events, startDate, endDate, getLODFromScale(0.5));
    };

    initApp();

    return () => {
      if (appRef.current) {
        appRef.current.destroy(true);
        appRef.current = null;
      }
    };
  }, [width, height]);

  // Re-render when events or LOD changes
  useEffect(() => {
    if (viewportRef.current) {
      renderContent(viewportRef.current, events, startDate, endDate, currentLOD);
    }
  }, [events, currentLOD, startDate, endDate]);

  // Handle window resize
  useEffect(() => {
    const handleResize = () => {
      if (appRef.current && viewportRef.current) {
        appRef.current.renderer.resize(width, height);
        viewportRef.current.resize(width, height);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [width, height]);

  const renderContent = useCallback(
    (
      viewport: Viewport,
      events: MaintenanceEvent[],
      startDate: Date,
      endDate: Date,
      lod: LODLevel
    ) => {
      // Clear existing children except the viewport container
      viewport.removeChildren();

      // Create container for all content
      const contentContainer = new Container();
      viewport.addChild(contentContainer);

      // Render based on LOD level
      switch (lod) {
        case 0:
          renderStrategicView(contentContainer, events, startDate, endDate);
          break;
        case 1:
          renderTacticalView(contentContainer, events, startDate, endDate);
          break;
        case 2:
          renderOperationalView(contentContainer, events, startDate, endDate);
          break;
        case 3:
          renderExecutionView(contentContainer, events, startDate, endDate, onEventSelect, onEventHover);
          break;
      }

      // Add timeline ruler
      renderTimelineRuler(contentContainer, startDate, endDate, lod);
    },
    [onEventSelect, onEventHover]
  );

  return (
    <div style={{ position: 'relative' }}>
      {/* Canvas container */}
      <div ref={containerRef} style={{ borderRadius: 4, overflow: 'hidden' }} />

      {/* Overlay controls */}
      <Card
        elevation={Elevation.TWO}
        style={{
          position: 'absolute',
          top: 16,
          left: 16,
          padding: 12,
          backgroundColor: 'rgba(255, 255, 255, 0.95)',
        }}
      >
        <div style={{ fontSize: 12, color: '#5c7080', marginBottom: 4 }}>LOD Level</div>
        <div style={{ fontSize: 14, fontWeight: 500, color: '#182026' }}>
          {LOD_LABELS[currentLOD as keyof typeof LOD_LABELS]}
        </div>
        <div style={{ fontSize: 12, color: '#8a9ba8', marginTop: 4 }}>
          Scale: {(scale * 100).toFixed(0)}%
        </div>
      </Card>

      {/* Zoom controls */}
      <div style={{ position: 'absolute', bottom: 16, right: 16, display: 'flex', gap: 8 }}>
        <Button
          onClick={() => viewportRef.current?.zoomPercent(0.2, true)}
          style={{ minWidth: 36 }}
        >
          +
        </Button>
        <Button
          onClick={() => viewportRef.current?.zoomPercent(-0.2, true)}
          style={{ minWidth: 36 }}
        >
          -
        </Button>
        <Button
          small
          onClick={() => {
            viewportRef.current?.fit();
            viewportRef.current?.moveCenter(width / 2, height / 2);
          }}
        >
          Fit
        </Button>
      </div>
    </div>
  );
}

// LOD 0: Strategic View (10-12 years) - Heatmap aggregation
function renderStrategicView(
  container: Container,
  events: MaintenanceEvent[],
  startDate: Date,
  endDate: Date
) {
  const graphics = new Graphics();
  container.addChild(graphics);

  // Calculate yearly aggregations
  const yearlyData = new Map<number, { PM1: number; PM2: number; HM: number; OVH: number }>();

  events.forEach((event) => {
    const year = event.startDate.getFullYear();
    if (!yearlyData.has(year)) {
      yearlyData.set(year, { PM1: 0, PM2: 0, HM: 0, OVH: 0 });
    }
    const data = yearlyData.get(year)!;
    data[event.type]++;
  });

  // Render yearly blocks
  const years = Array.from(yearlyData.keys()).sort();
  const blockWidth = 100;
  const blockHeight = 80;

  years.forEach((year, index) => {
    const data = yearlyData.get(year)!;
    const total = data.PM1 + data.PM2 + data.HM + data.OVH;
    const intensity = Math.min(1, total / 50); // Normalize

    graphics.rect(
      index * (blockWidth + 10) + 20,
      HEADER_HEIGHT,
      blockWidth,
      blockHeight
    );
