// LOD 3: Execution View (1-4 weeks) - Full task details
function renderExecutionView(
  container: Container,
  events: MaintenanceEvent[],
  startDate: Date,
  endDate: Date,
  onEventSelect?: (event: MaintenanceEvent) => void,
  onEventHover?: (event: MaintenanceEvent | null) => void
) {
  const graphics = new Graphics();
  container.addChild(graphics);

  // Group by train
  const trainGroups = new Map<string, MaintenanceEvent[]>();
  events.forEach((event) => {
    if (!trainGroups.has(event.trainId)) {
      trainGroups.set(event.trainId, []);
    }
    trainGroups.get(event.trainId)!.push(event);
  });

  const trains = Array.from(trainGroups.keys()).slice(0, 20);
  const startTime = startDate.getTime();
