'use client';

import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Application, Container, Graphics, Text, TextStyle } from 'pixi.js';
import { Viewport } from 'pixi-viewport';
import {
  LODLevel,
  getLODFromScale,
} from '@/stores/viewportStore';

interface MaintenanceEvent {
  id: string;
  trainId: string;
  trainName: string;
  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
  startDate: Date;
  endDate: Date;
  depot: string;
}

interface ScheduleCanvasProps {
  events: MaintenanceEvent[];
  onEventSelect?: (event: MaintenanceEvent) => void;
  onEventHover?: (event: MaintenanceEvent | null) => void;
  startDate?: Date;
  endDate?: Date;
  width?: number;
  height?: number;
}

// Color palette for maintenance types
const MAINTENANCE_COLORS = {
  PM1: 0x10B981, // Green
  PM2: 0x3B82F6, // Blue
  HM: 0xF59E0B,  // Amber
  OVH: 0xEF4444, // Red
};

// LOD level descriptions
const LOD_LABELS = {
  0: 'Strategic (10-12 years)',
  1: 'Tactical (1-3 years)',
  2: 'Operational (1-6 months)',
  3: 'Execution (1-4 weeks)',
};

// Day width in pixels at scale 1.0
const DAY_WIDTH = 20;
const ROW_HEIGHT = 40;
const HEADER_HEIGHT = 60;

export function ScheduleCanvas({
  events,
  onEventSelect,
  onEventHover,
  startDate = new Date(),
  endDate = new Date(Date.now() + 365 * 24 * 60 * 60 * 1000),
  width = 1200,
  height = 600,
}: ScheduleCanvasProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const appRef = useRef<Application | null>(null);
  const viewportRef = useRef<Viewport | null>(null);

  // Use local state for LOD and scale to avoid toolkit infinite loop issue
  const [currentLOD, setCurrentLOD] = useState<LODLevel>(2);
  const [scale, setScale] = useState(0.5);

  // Initialize Pixi application
  useEffect(() => {
    if (!containerRef.current) return;

    const app = new Application();

    const initApp = async () => {
      await app.init({
        width,
        height,
        backgroundColor: 0x0A0A0A, // Dark canvas background
        resolution: window.devicePixelRatio || 1,
        autoDensity: true,
        antialias: true,
      });

      containerRef.current?.appendChild(app.canvas);
      appRef.current = app;

      // Create viewport
      const viewport = new Viewport({
        screenWidth: width,
        screenHeight: height,
        worldWidth: width * 10,
        worldHeight: height * 5,
        events: app.renderer.events,
      });

      app.stage.addChild(viewport);
      viewportRef.current = viewport;

      // Enable viewport interactions
      viewport
        .drag()
        .pinch()
        .wheel()
        .decelerate()
        .clampZoom({
          minScale: 0.05,
          maxScale: 4.0,
        });

      // Listen to zoom/scale changes - update local state
      viewport.on('zoomed', () => {
        const newScale = viewport.scale.x;
        setScale(newScale);
        setCurrentLOD(getLODFromScale(newScale));
      });

      viewport.on('moved', () => {
        // Position tracking handled by viewport internally
      });

      // Initial render
      renderContent(viewport, events, startDate, endDate, getLODFromScale(0.5));
    };

    initApp();

    return () => {
      if (appRef.current) {
        appRef.current.destroy(true);
        appRef.current = null;
      }
    };
  }, [width, height]);

  // Re-render when events or LOD changes
  useEffect(() => {
    if (viewportRef.current) {
      renderContent(viewportRef.current, events, startDate, endDate, currentLOD);
    }
  }, [events, currentLOD, startDate, endDate]);

  // Handle window resize
  useEffect(() => {
    const handleResize = () => {
      if (appRef.current && viewportRef.current) {
        appRef.current.renderer.resize(width, height);
        viewportRef.current.resize(width, height);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [width, height]);

  const renderContent = useCallback(
    (
      viewport: Viewport,
      events: MaintenanceEvent[],
      startDate: Date,
      endDate: Date,
      lod: LODLevel
    ) => {
      // Clear existing children except the viewport container
      viewport.removeChildren();

      // Create container for all content
      const contentContainer = new Container();
      viewport.addChild(contentContainer);

      // Render based on LOD level
      switch (lod) {
        case 0:
          renderStrategicView(contentContainer, events, startDate, endDate);
          break;
        case 1:
          renderTacticalView(contentContainer, events, startDate, endDate);
          break;
        case 2:
          renderOperationalView(contentContainer, events, startDate, endDate);
          break;
        case 3:
          renderExecutionView(contentContainer, events, startDate, endDate, onEventSelect, onEventHover);
          break;
      }

      // Add timeline ruler
      renderTimelineRuler(contentContainer, startDate, endDate, lod);
    },
    [onEventSelect, onEventHover]
  );

  return (
    <div className="relative">
      {/* Canvas container */}
      <div ref={containerRef} className="rounded-lg overflow-hidden" />

      {/* Overlay controls */}
      <div className="absolute top-4 left-4 bg-panel/90 backdrop-blur-sm rounded-lg p-3 space-y-2">
        <div className="text-xs text-text-secondary">LOD Level</div>
        <div className="text-sm font-medium text-text-primary">
          {LOD_LABELS[currentLOD as keyof typeof LOD_LABELS]}
        </div>
        <div className="text-xs text-text-muted">
          Scale: {(scale * 100).toFixed(0)}%
        </div>
      </div>

      {/* Zoom controls */}
      <div className="absolute bottom-4 right-4 flex gap-2">
        <button
          onClick={() => viewportRef.current?.zoomPercent(0.2, true)}
          className="p-2 bg-panel hover:bg-elevated rounded text-text-primary"
        >
          +
        </button>
        <button
          onClick={() => viewportRef.current?.zoomPercent(-0.2, true)}
          className="p-2 bg-panel hover:bg-elevated rounded text-text-primary"
        >
          -
        </button>
        <button
          onClick={() => {
            viewportRef.current?.fit();
            viewportRef.current?.moveCenter(width / 2, height / 2);
          }}
          className="p-2 bg-panel hover:bg-elevated rounded text-text-primary text-xs"
        >
          Fit
        </button>
      </div>
    </div>
  );
}

