      eventGraphics.on('pointerout', () => {
        eventGraphics.alpha = 1;
        onEventHover?.(null);
      });

      eventGraphics.on('pointertap', () => {
        onEventSelect?.(event);
      });

      container.addChild(eventGraphics);

      // Event type label
      if (width > 40) {
        const typeStyle = new TextStyle({
          fontSize: 10,
          fill: 0xFFFFFF,
          fontWeight: 'bold',
          fontFamily: 'Inter',
        });
        const typeText = new Text({ text: event.type, style: typeStyle });
        typeText.x = x + 5;
        typeText.y = y + 8;
        container.addChild(typeText);

        // Depot label
        if (width > 80) {
          const depotStyle = new TextStyle({
            fontSize: 9,
            fill: 0xCCCCCC, // Lighter color instead of alpha
            fontFamily: 'Inter',
          });
          const depotText = new Text({ text: event.depot, style: depotStyle });
          depotText.x = x + 5;
          depotText.y = y + 22;
          container.addChild(depotText);
        }
      }
    });
  });
}

// Timeline ruler
function renderTimelineRuler(
  container: Container,
  startDate: Date,
  endDate: Date,
  lod: LODLevel
) {
  const graphics = new Graphics();
  container.addChild(graphics);

  // Header background
  graphics.rect(0, 0, 3000, HEADER_HEIGHT);
  graphics.fill({ color: 0x1C1C1C });

  const style = new TextStyle({
    fontSize: 11,
    fill: 0xA1A1A1,
    fontFamily: 'Inter',
  });

  // Different granularity based on LOD
  const msPerDay = 24 * 60 * 60 * 1000;
  const startTime = startDate.getTime();

  if (lod >= 2) {
    // Show months
    const months = [];
    let current = new Date(startDate);
    while (current < endDate) {
      months.push(new Date(current));
      current.setMonth(current.getMonth() + 1);
    }

    months.forEach((month, index) => {
      const offset = (month.getTime() - startTime) / msPerDay;
      const x = 150 + offset * DAY_WIDTH * (lod === 3 ? 2 : 1);

      // Month line
      graphics.moveTo(x, HEADER_HEIGHT - 20);
      graphics.lineTo(x, HEADER_HEIGHT);
      graphics.stroke({ color: 0x2A2A2A, width: 1 });

      // Month label
      const monthLabel = month.toLocaleDateString('en-US', {
        month: 'short',
        year: '2-digit',
      });
      const text = new Text({ text: monthLabel, style });
      text.x = x + 5;
      text.y = HEADER_HEIGHT - 18;
      container.addChild(text);
    });
  }
}

export default ScheduleCanvas;

